/* ============================================================
   Verb Tenses Data — Part 2 (Tenses 7–12)
   Past Perfect, Past Perfect Continuous, Simple Future,
   Future Continuous, Future Perfect, Future Perfect Continuous
   510 exercises total (85 per tense)
   For PTE Academic Study Planner
   ============================================================ */

var VERB_TENSES_2 = [
  /* ──────────────────────────────────────────────────────────────
     1. PAST PERFECT
     ────────────────────────────────────────────────────────────── */
  {
    id: "past-perfect",
    name: "Past Perfect",
    formula: "Subject + had + past participle",
    negFormula: "Subject + had + not + past participle",
    qFormula: "Had + subject + past participle?",
    usage: ["Action completed before another past action", "Third conditional", "Reported speech (backshift)", "Expressing regret with 'wish'"],
    signalWords: ["before", "after", "by the time", "already", "just", "never", "until", "when", "once", "as soon as"],
    examples: {pos: "She had finished her research before the deadline.", neg: "She had not finished before noon.", q: "Had she finished before the deadline?"},
    exercises: [
      {id:"pap001", type:"fill", q:"The students ___ (complete) the assignment before the teacher collected it.", a:"had completed", exp:"The past perfect 'had completed' shows the assignment was finished before the teacher's collection (a later past action)."},
      {id:"pap002", type:"fill", q:"By the time the lecture started, most attendees ___ (arrive).", a:"had arrived", exp:"'By the time' signals that one past event (arriving) was completed before another (the lecture starting)."},
      {id:"pap003", type:"fill", q:"The researcher ___ (publish) three papers before she received tenure.", a:"had published", exp:"Publishing happened before receiving tenure, so past perfect is needed for the earlier action."},
      {id:"pap004", type:"fill", q:"The government ___ (already / announce) the policy change when the media reported it.", a:"had already announced", exp:"'Already' combined with two past events requires past perfect for the earlier action."},
      {id:"pap005", type:"fill", q:"After the hospital ___ (implement) new safety protocols, infection rates dropped.", a:"had implemented", exp:"'After' introduces the earlier completed action, requiring past perfect."},
      {id:"pap006", type:"fill", q:"The environmental agency ___ (never / record) such high pollution levels before 2020.", a:"had never recorded", exp:"'Never ... before' with a past time reference requires past perfect to show the action had not occurred up to that point."},
      {id:"pap007", type:"fill", q:"Once the city ___ (install) solar panels on public buildings, energy costs decreased.", a:"had installed", exp:"'Once' introduces the completed earlier action; past perfect shows it was finished before costs decreased."},
      {id:"pap008", type:"fill", q:"The university ___ (not / update) its curriculum for a decade before the reform.", a:"had not updated", exp:"The negative past perfect shows a lack of action over a period before the reform (another past event)."},
      {id:"pap009", type:"fill", q:"She wished she ___ (study) harder for the PTE exam.", a:"had studied", exp:"'Wish' + past perfect expresses regret about a past action that cannot be changed."},
      {id:"pap010", type:"fill", q:"By 2019, the organisation ___ (raise) over two million dollars for public health.", a:"had raised", exp:"'By 2019' sets a past deadline before which the raising was completed, requiring past perfect."},
      {id:"pap011", type:"fill", q:"The scientists ___ (just / discover) the new species when funding was cut.", a:"had just discovered", exp:"'Just' emphasises that the discovery happened only moments before funding was cut."},
      {id:"pap012", type:"fill", q:"The school ___ (introduce) digital learning tools before the pandemic forced remote education.", a:"had introduced", exp:"Past perfect marks the earlier event (introducing tools) that preceded the later past event (the pandemic)."},
      {id:"pap013", type:"fill", q:"Until the report was released, no one ___ (realise) the extent of the damage.", a:"had realised", exp:"'Until' with a past event signals that the realisation had not happened before the report's release."},
      {id:"pap014", type:"fill", q:"The committee ___ (review) all applications before the interviews began.", a:"had reviewed", exp:"Reviewing was completed before the interviews started; past perfect marks the earlier action."},
      {id:"pap015", type:"fill", q:"He reported that the government ___ (invest) heavily in renewable energy.", a:"had invested", exp:"Reported speech requires backshift: past simple 'invested' becomes past perfect 'had invested'."},
      {id:"pap016", type:"fill", q:"If the city ___ (plan) better, the flooding would not have been so severe.", a:"had planned", exp:"Third conditional uses 'if + past perfect' for an unreal past condition."},
      {id:"pap017", type:"fill", q:"The doctor explained that the patient ___ (not / follow) the prescribed treatment.", a:"had not followed", exp:"Reported speech with backshift: the doctor's original statement used past simple, which shifts to past perfect."},
      {id:"pap018", type:"fill", q:"As soon as the government ___ (approve) the budget, construction began.", a:"had approved", exp:"'As soon as' introduces the earlier completed action before construction began."},
      {id:"pap019", type:"fill", q:"The students ___ (not / learn) about climate change before the new syllabus was adopted.", a:"had not learned", exp:"Negative past perfect shows the absence of learning before the syllabus adoption."},
      {id:"pap020", type:"fill", q:"By the time technology ___ (transform) healthcare, many lives ___ (already / be) lost.", a:"had transformed ... had already been", exp:"Both actions precede an implied later reference point; 'by the time' and 'already' both trigger past perfect."},
      {id:"pap021", type:"fill", q:"The economist said that inflation ___ (rise) sharply over the previous quarter.", a:"had risen", exp:"Reported speech backshift: 'rose' in direct speech becomes 'had risen' in reported speech."},
      {id:"pap022", type:"fill", q:"She ___ (never / travel) overseas before she enrolled in the exchange programme.", a:"had never travelled", exp:"'Never ... before' with a past reference requires past perfect. Note Australian spelling: 'travelled', 'programme'."},
      {id:"pap023", type:"fill", q:"The company ___ (already / relocate) its headquarters when the tax law changed.", a:"had already relocated", exp:"'Already' signals the relocation was complete before the tax law change."},
      {id:"pap024", type:"fill", q:"If they ___ (recognise) the warning signs earlier, the crisis could have been avoided.", a:"had recognised", exp:"Third conditional: 'if + had + past participle' for an unreal past condition. Australian spelling: 'recognise'."},
      {id:"pap025", type:"fill", q:"The nurse confirmed that the patient ___ (receive) all required vaccinations.", a:"had received", exp:"Reported speech backshift from 'received' to 'had received'."},
      {id:"pap026", type:"mc", q:"Choose the correct sentence:", options:["After the bell had rang, students left the classroom.","After the bell had rung, students left the classroom.","After the bell has rung, students left the classroom.","After the bell rung, students left the classroom."], a:1, exp:"'Rung' is the correct past participle of 'ring'. 'Rang' is simple past and cannot follow 'had'."},
      {id:"pap027", type:"mc", q:"Which sentence correctly uses the past perfect?", options:["She had went to the library before it closed.","She had gone to the library before it closed.","She has gone to the library before it closed.","She gone to the library before it closed."], a:1, exp:"'Gone' is the correct past participle of 'go'. 'Went' is simple past and cannot follow 'had'."},
      {id:"pap028", type:"mc", q:"'By the time the ambulance arrived, the paramedics ___ first aid.' Choose the best option.", options:["already provided","had already provided","have already provided","already provide"], a:1, exp:"'By the time' + past event requires past perfect for the action completed before arrival."},
      {id:"pap029", type:"mc", q:"Which is the correct backshift in reported speech? Direct: 'I finished the report.'", options:["He said he finished the report.","He said he had finished the report.","He said he has finished the report.","He said he was finished the report."], a:1, exp:"In reported speech, simple past 'finished' shifts to past perfect 'had finished'."},
      {id:"pap030", type:"mc", q:"Choose the correct third conditional:", options:["If they studied more, they would have passed.","If they had studied more, they would have passed.","If they have studied more, they would have passed.","If they would have studied more, they would have passed."], a:1, exp:"Third conditional: if + had + past participle, ... would have + past participle."},
      {id:"pap031", type:"mc", q:"The government announced that it ___ new environmental regulations.", options:["implemented","had implemented","has implemented","implements"], a:1, exp:"Reported speech requires backshift from past simple to past perfect."},
      {id:"pap032", type:"mc", q:"'She wished she ___ the scholarship application on time.' Choose correctly.", options:["submitted","had submitted","has submitted","would submit"], a:1, exp:"'Wish' + past perfect expresses regret about a completed past action."},
      {id:"pap033", type:"mc", q:"Which sentence is grammatically correct?", options:["Before the policy changed, emissions had been reduced by 20%.","Before the policy changed, emissions have been reduced by 20%.","Before the policy changed, emissions were been reduced by 20%.","Before the policy changed, emissions are reduced by 20%."], a:0, exp:"Past perfect passive 'had been reduced' correctly marks the earlier action before the policy change."},
      {id:"pap034", type:"mc", q:"'Once the data ___, the researchers published their findings.'", options:["had been analysed","was been analysed","has been analysed","had been analyse"], a:0, exp:"Past perfect passive: had + been + past participle. Australian spelling: 'analysed'."},
      {id:"pap035", type:"mc", q:"Identify the correct use of past perfect:", options:["I had eaten breakfast, then I went to work.","I ate breakfast after I had went to work.","I had eat breakfast before going to work.","I have had eaten breakfast before work."], a:0, exp:"'Had eaten' correctly precedes the later action 'went to work'. Option B uses 'went' instead of 'gone'."},
      {id:"pap036", type:"mc", q:"'The teacher said that the students ___ their homework.' Choose the correct form.", options:["did not do","had not done","have not done","do not do"], a:1, exp:"Reported speech backshift: 'did not do' becomes 'had not done'."},
      {id:"pap037", type:"mc", q:"Choose the sentence with correct past perfect usage:", options:["By the time I arrived, the meeting had already started.","By the time I arrived, the meeting has already started.","By the time I arrived, the meeting already started.","By the time I had arrived, the meeting had already started."], a:0, exp:"'By the time' + simple past requires past perfect for the earlier action. Option D incorrectly uses past perfect in both clauses."},
      {id:"pap038", type:"mc", q:"'If the hospital ___ more staff, the waiting times would not have been so long.'", options:["hired","had hired","has hired","would hire"], a:1, exp:"Third conditional requires 'if + had + past participle' in the condition clause."},
      {id:"pap039", type:"mc", q:"Which is correct? 'The researcher discovered that the previous study ___.'", options:["contained errors","had contained errors","has contained errors","was containing errors"], a:1, exp:"Reported speech backshift: the discovery (past) reports on a study that contained errors (earlier past), requiring past perfect."},
      {id:"pap040", type:"mc", q:"'___ the council approved the project before the deadline?'", options:["Has","Had","Did","Was"], a:1, exp:"Past perfect question form: 'Had + subject + past participle?'"},
      {id:"pap041", type:"mc", q:"Select the correct option: 'Until technology ___ traditional methods, most farmers relied on manual labour.'", options:["replaced","had replaced","has replaced","replaces"], a:1, exp:"'Until' with a past reference requires past perfect for the action completed before the main clause event."},
      {id:"pap042", type:"mc", q:"'The patient ___ several treatments before the correct diagnosis was made.'", options:["undergoes","had undergone","has undergone","was undergone"], a:1, exp:"Past perfect shows the treatments happened before the diagnosis, which is also in the past."},
      {id:"pap043", type:"mc", q:"Which sentence correctly expresses regret?", options:["I wish I organised my time better last semester.","I wish I had organised my time better last semester.","I wish I have organised my time better last semester.","I wish I would organise my time better last semester."], a:1, exp:"'Wish' + past perfect for past regret. Australian spelling: 'organised'."},
      {id:"pap044", type:"mc", q:"'She ___ never ___ such a comprehensive health programme before joining that clinic.'", options:["has ... seen","had ... seen","was ... seeing","did ... see"], a:1, exp:"'Never ... before' with a past joining event requires past perfect 'had never seen'."},
      {id:"pap045", type:"mc", q:"Choose the correct passive past perfect: 'By 2015, the old curriculum ___.'", options:["had been revised","has been revised","was been revised","had revised"], a:0, exp:"Past perfect passive: 'had been + past participle'. The curriculum was revised (by someone) before 2015."},
      {id:"pap046", type:"mc", q:"'After the government ___ the new tax, public spending increased.'", options:["introduced","had introduced","has introduced","was introducing"], a:1, exp:"'After' introduces the earlier action requiring past perfect before the main clause in simple past."},
      {id:"pap047", type:"mc", q:"Identify the error: 'If I would have known about the scholarship, I would have applied.'", options:["'would have known' should be 'had known'","'would have applied' should be 'applied'","There is no error.","'known' should be 'knew'"], a:0, exp:"Third conditional: the condition clause requires 'if + had + past participle', not 'if + would have'. This is a common error among Chinese speakers."},
      {id:"pap048", type:"mc", q:"'The data showed that air quality ___ significantly since the factory had closed.'", options:["improved","had improved","has improved","improves"], a:1, exp:"Reported speech with backshift. The improvement occurred before the data showed it."},
      {id:"pap049", type:"mc", q:"'The city council confirmed that all safety inspections ___.'", options:["were completed","had been completed","have been completed","completed"], a:1, exp:"Reported speech requires backshift: 'have been completed' becomes 'had been completed'."},
      {id:"pap050", type:"mc", q:"Which sentence uses past perfect correctly to show cause and effect?", options:["The bridge collapsed because the engineers had ignored the warning signs.","The bridge collapsed because the engineers ignored the warning signs.","The bridge collapsed because the engineers have ignored the warning signs.","The bridge had collapsed because the engineers ignored the warning signs."], a:0, exp:"Past perfect in the 'because' clause shows the ignoring happened before the collapse, establishing clear cause and effect."},
      {id:"pap051", type:"error", q:"After the lecture had began, latecomers were not permitted to enter.", a:"After the lecture had begun, latecomers were not permitted to enter.", exp:"'Begun' is the correct past participle of 'begin'. 'Began' is the simple past form and cannot follow 'had'."},
      {id:"pap052", type:"error", q:"The students have completed the experiment before the lab closed yesterday.", a:"The students had completed the experiment before the lab closed yesterday.", exp:"With 'yesterday' (a past time marker) and 'before', past perfect 'had completed' is needed, not present perfect."},
      {id:"pap053", type:"error", q:"If the government would have invested in education, outcomes would have improved.", a:"If the government had invested in education, outcomes would have improved.", exp:"Third conditional requires 'if + had + past participle', not 'if + would have + past participle'. This is a very common error."},
      {id:"pap054", type:"error", q:"She wished she took the opportunity to study abroad.", a:"She wished she had taken the opportunity to study abroad.", exp:"'Wish' + past perfect for past regret. 'Took' (simple past) should be 'had taken' (past perfect)."},
      {id:"pap055", type:"error", q:"By the time the ambulance arrived, the patient has already lost consciousness.", a:"By the time the ambulance arrived, the patient had already lost consciousness.", exp:"'By the time' + past event requires past perfect, not present perfect, for the earlier action."},
      {id:"pap056", type:"error", q:"The researcher found that the previous team did not analyse the data correctly.", a:"The researcher found that the previous team had not analysed the data correctly.", exp:"Reported speech backshift: 'did not analyse' should become 'had not analysed'. Australian spelling: 'analyse'."},
      {id:"pap057", type:"error", q:"Once the policy had been implement, crime rates decreased.", a:"Once the policy had been implemented, crime rates decreased.", exp:"Past perfect passive requires 'had been + past participle'. 'Implement' should be 'implemented'."},
      {id:"pap058", type:"error", q:"The hospital reported that patient satisfaction improves after the renovation.", a:"The hospital reported that patient satisfaction had improved after the renovation.", exp:"Reported speech backshift: 'improves' (present) shifts to 'had improved' (past perfect) after a past reporting verb."},
      {id:"pap059", type:"error", q:"Never the city had experienced such severe flooding before the 2019 disaster.", a:"Never had the city experienced such severe flooding before the 2019 disaster.", exp:"When 'never' begins a sentence, inversion is required: 'Never had + subject + past participle'."},
      {id:"pap060", type:"error", q:"Before the new curriculum was adopted, the school did not have updated its materials for years.", a:"Before the new curriculum was adopted, the school had not updated its materials for years.", exp:"Past perfect negative: 'had not + past participle'. 'Did not have updated' is not a valid construction."},
      {id:"pap061", type:"error", q:"The teacher said that the class already finished the chapter.", a:"The teacher said that the class had already finished the chapter.", exp:"Reported speech backshift: 'finished' becomes 'had finished' after a past reporting verb."},
      {id:"pap062", type:"error", q:"If they had took the environmental warnings seriously, the damage could have been prevented.", a:"If they had taken the environmental warnings seriously, the damage could have been prevented.", exp:"'Taken' is the correct past participle of 'take'. 'Took' is simple past and cannot follow 'had'."},
      {id:"pap063", type:"error", q:"The company already spent millions on research before the product was launched.", a:"The company had already spent millions on research before the product was launched.", exp:"'Already' with 'before' and a past event requires past perfect for the earlier action."},
      {id:"pap064", type:"error", q:"Until the government had not intervened, the crisis continued to worsen.", a:"Until the government intervened, the crisis had continued to worsen.", exp:"'Until' marks the turning point. The continuing action before the intervention takes past perfect; 'had not intervened' creates a double negative logic error."},
      {id:"pap065", type:"error", q:"He said he has never seen such a well-organised healthcare system.", a:"He said he had never seen such a well-organised healthcare system.", exp:"Reported speech backshift: 'has never seen' becomes 'had never seen' after a past reporting verb."},
      {id:"pap066", type:"error", q:"After the project had been complete, the team celebrated their success.", a:"After the project had been completed, the team celebrated their success.", exp:"Past perfect passive requires the past participle 'completed', not the base form 'complete'."},
      {id:"pap067", type:"error", q:"The students did not realise they had made a mistake until the results was published.", a:"The students had not realised they had made a mistake until the results were published.", exp:"Two corrections: 'did not realise' should be 'had not realised' (past perfect for the earlier state), and 'was' should be 'were' (plural subject 'results')."},
      {id:"pap068", type:"error", q:"The economist claimed that the recession had began in the previous year.", a:"The economist claimed that the recession had begun in the previous year.", exp:"'Begun' is the correct past participle of 'begin'. 'Began' is simple past form."},
      {id:"pap069", type:"error", q:"If I had knew about the scholarship earlier, I would have applied.", a:"If I had known about the scholarship earlier, I would have applied.", exp:"'Known' is the correct past participle of 'know'. 'Knew' is simple past and cannot follow 'had'."},
      {id:"pap070", type:"error", q:"By the time the technology was widely adopted, many companies already closed down.", a:"By the time the technology was widely adopted, many companies had already closed down.", exp:"'By the time' + past event requires past perfect 'had already closed' for the earlier action."},
      {id:"pap071", type:"transform", q:"The government introduced the policy. Then public opinion shifted. [Combine using 'after' + past perfect]", a:"After the government had introduced the policy, public opinion shifted.", exp:"'After' + past perfect for the first action, simple past for the second action."},
      {id:"pap072", type:"transform", q:"She submitted the thesis. The supervisor requested changes. (She submitted first.) [Rewrite using 'before']", a:"She had submitted the thesis before the supervisor requested changes.", exp:"Past perfect for the earlier action ('had submitted'), simple past for the later action."},
      {id:"pap073", type:"transform", q:"Direct speech: 'I completed the health assessment,' the nurse said. [Change to reported speech]", a:"The nurse said that she had completed the health assessment.", exp:"Reported speech backshift: 'completed' becomes 'had completed'."},
      {id:"pap074", type:"transform", q:"I didn't attend the environmental seminar. I regret it now. [Rewrite using 'wish']", a:"I wish I had attended the environmental seminar.", exp:"'Wish' + past perfect to express regret about a past decision."},
      {id:"pap075", type:"transform", q:"The hospital did not hire enough staff. The waiting times were long. [Rewrite as a third conditional]", a:"If the hospital had hired enough staff, the waiting times would not have been so long.", exp:"Third conditional: 'if + had + past participle' for the unreal condition, 'would have + past participle' for the unreal result."},
      {id:"pap076", type:"transform", q:"All the tickets were sold. We arrived at the venue. (Tickets sold first.) [Combine using 'by the time']", a:"By the time we arrived at the venue, all the tickets had been sold.", exp:"'By the time' + simple past, then past perfect passive for the action completed before arrival."},
      {id:"pap077", type:"transform", q:"The city built a new public transport system. Traffic congestion decreased. [Combine using 'once' + past perfect]", a:"Once the city had built a new public transport system, traffic congestion decreased.", exp:"'Once' + past perfect for the completed earlier action, simple past for the result."},
      {id:"pap078", type:"transform", q:"The students didn't study the material. They failed the exam. [Rewrite as a third conditional]", a:"If the students had studied the material, they would not have failed the exam.", exp:"Third conditional: unreal past condition with 'if + had + past participle'."},
      {id:"pap079", type:"transform", q:"Direct speech: 'We analysed the environmental data,' the scientists reported. [Change to reported speech]", a:"The scientists reported that they had analysed the environmental data.", exp:"Reported speech backshift: 'analysed' becomes 'had analysed'. Australian spelling: 'analysed'."},
      {id:"pap080", type:"transform", q:"The research team collected all samples. Then they began the analysis. [Combine using 'after']", a:"After the research team had collected all samples, they began the analysis.", exp:"'After' + past perfect for the first action, simple past for the second."},
      {id:"pap081", type:"transform", q:"I didn't prepare properly for the speaking test. I regret it. [Rewrite using 'wish']", a:"I wish I had prepared properly for the speaking test.", exp:"'Wish' + past perfect expresses regret about an unchangeable past action."},
      {id:"pap082", type:"transform", q:"The government provided subsidies. Then renewable energy adoption increased. [Combine using 'as soon as']", a:"As soon as the government had provided subsidies, renewable energy adoption increased.", exp:"'As soon as' + past perfect for the completed earlier action, simple past for the following event."},
      {id:"pap083", type:"transform", q:"She didn't learn to manage her time. She struggled in university. [Rewrite as a third conditional]", a:"If she had learned to manage her time, she would not have struggled in university.", exp:"Third conditional for an unreal past situation with a different imagined outcome."},
      {id:"pap084", type:"transform", q:"Direct speech: 'The programme improved student outcomes,' the principal stated. [Change to reported speech]", a:"The principal stated that the programme had improved student outcomes.", exp:"Reported speech backshift: 'improved' becomes 'had improved'. Australian spelling: 'programme'."},
      {id:"pap085", type:"transform", q:"The company completed all safety checks. The factory reopened. [Combine using 'not until ... had ... did']", a:"Not until the company had completed all safety checks did the factory reopen.", exp:"'Not until' + past perfect triggers inversion in the main clause: 'did + subject + base verb'."}
    ]
  },

  /* ──────────────────────────────────────────────────────────────
     2. PAST PERFECT CONTINUOUS
     ────────────────────────────────────────────────────────────── */
  {
    id: "past-perfect-continuous",
    name: "Past Perfect Continuous",
    formula: "Subject + had + been + verb-ing",
    negFormula: "Subject + had + not + been + verb-ing",
    qFormula: "Had + subject + been + verb-ing?",
    usage: ["Duration of action before another past event", "Cause of a past result", "Emphasising how long something lasted"],
    signalWords: ["for", "since", "how long", "before", "when", "by the time", "all day", "all week"],
    examples: {pos: "She had been studying for three hours before the test.", neg: "She had not been waiting long.", q: "Had she been studying all morning?"},
    exercises: [
      {id:"papc001", type:"fill", q:"The researchers ___ (work) on the project for two years before they published their findings.", a:"had been working", exp:"Past perfect continuous shows the duration of work (two years) leading up to the past event of publishing."},
      {id:"papc002", type:"fill", q:"She ___ (study) English for six months before she took the PTE exam.", a:"had been studying", exp:"'For six months' emphasises the duration of studying before the exam (a past event)."},
      {id:"papc003", type:"fill", q:"The government ___ (invest) in healthcare infrastructure for a decade before the results became visible.", a:"had been investing", exp:"The continuous form emphasises the ongoing nature of investment over a long period before results appeared."},
      {id:"papc004", type:"fill", q:"By the time the new principal arrived, the school ___ (struggle) with low enrolment for years.", a:"had been struggling", exp:"'By the time' + 'for years' signals duration of an ongoing action before a past event."},
      {id:"papc005", type:"fill", q:"The patient ___ (experience) symptoms for weeks before seeking medical advice.", a:"had been experiencing", exp:"The continuous form emphasises the ongoing duration of symptoms before the past action of seeking advice."},
      {id:"papc006", type:"fill", q:"The students ___ (prepare) for the examination all week when the schedule was suddenly changed.", a:"had been preparing", exp:"'All week' shows the duration of preparation before the sudden schedule change."},
      {id:"papc007", type:"fill", q:"Scientists ___ (monitor) the volcano for months before it finally erupted.", a:"had been monitoring", exp:"'For months' emphasises the ongoing monitoring before the eruption."},
      {id:"papc008", type:"fill", q:"The city ___ (plan) the new transport system for years before construction commenced.", a:"had been planning", exp:"Past perfect continuous shows extended planning duration before the commencement of construction."},
      {id:"papc009", type:"fill", q:"He ___ (teach) at the university for fifteen years before he retired.", a:"had been teaching", exp:"'For fifteen years' emphasises the duration of the teaching career before retirement."},
      {id:"papc010", type:"fill", q:"The environmental organisation ___ (campaign) against deforestation since 2005 when the new law was passed.", a:"had been campaigning", exp:"'Since 2005' marks the starting point of the ongoing action before the law was passed."},
      {id:"papc011", type:"fill", q:"The children ___ (wait) in the rain for over an hour when the bus finally arrived.", a:"had been waiting", exp:"'For over an hour' stresses the duration of waiting before the bus arrived."},
      {id:"papc012", type:"fill", q:"Economists ___ (warn) about the housing bubble for years before it burst.", a:"had been warning", exp:"The continuous form highlights repeated, ongoing warnings over a period before the burst."},
      {id:"papc013", type:"fill", q:"She ___ (not / sleep) well for weeks, which explained her poor performance in the test.", a:"had not been sleeping", exp:"Negative past perfect continuous shows a lack of proper sleep over time, causing the past result."},
      {id:"papc014", type:"fill", q:"The factory ___ (pollute) the river for decades before regulators finally intervened.", a:"had been polluting", exp:"'For decades' shows long-term ongoing pollution before the intervention."},
      {id:"papc015", type:"fill", q:"By the time the technology was adopted, engineers ___ (develop) it for over five years.", a:"had been developing", exp:"'By the time' + 'for over five years' requires past perfect continuous for the duration of development."},
      {id:"papc016", type:"fill", q:"The community ___ (petition) the council for better facilities since the beginning of the year.", a:"had been petitioning", exp:"'Since the beginning of the year' marks the start of an ongoing action up to a past reference point."},
      {id:"papc017", type:"fill", q:"How long ___ the team ___ (negotiate) before the agreement was reached?", a:"had ... been negotiating", exp:"'How long' with past perfect continuous asks about the duration of an action before a past event."},
      {id:"papc018", type:"fill", q:"The nurse ___ (care) for elderly patients for twenty years when the hospital closed.", a:"had been caring", exp:"'For twenty years' emphasises the career duration before the hospital's closure."},
      {id:"papc019", type:"fill", q:"The professor ___ (research) the topic for a decade, which was why her lecture was so detailed.", a:"had been researching", exp:"The continuous form explains the cause (long research) of the past result (a detailed lecture)."},
      {id:"papc020", type:"fill", q:"Traffic ___ (build) up all morning before the accident made it even worse.", a:"had been building", exp:"'All morning' shows the duration of ongoing traffic congestion before the accident."},
      {id:"papc021", type:"fill", q:"The aid organisation ___ (provide) clean water to the village for three years when funding was cut.", a:"had been providing", exp:"'For three years' emphasises the ongoing provision before the past event of funding being cut."},
      {id:"papc022", type:"fill", q:"Residents ___ (complain) about noise pollution for months, so the council finally took action.", a:"had been complaining", exp:"Past perfect continuous shows the ongoing cause (complaining) that led to the past result (council action)."},
      {id:"papc023", type:"fill", q:"The student ___ (revise) all day, so she felt confident going into the exam.", a:"had been revising", exp:"'All day' shows the duration of revision that caused the feeling of confidence."},
      {id:"papc024", type:"fill", q:"The charity ___ (raise) funds since January when the target was finally met in June.", a:"had been raising", exp:"'Since January' marks the start of the ongoing action before the target was met."},
      {id:"papc025", type:"fill", q:"His eyes were red because he ___ (read) academic papers on his screen for hours.", a:"had been reading", exp:"Past perfect continuous explains the cause of a visible past result (red eyes)."},
      {id:"papc026", type:"mc", q:"Choose the correct sentence:", options:["She had been working at the clinic for ten years when she was promoted.","She had been work at the clinic for ten years when she was promoted.","She has been working at the clinic for ten years when she was promoted.","She had working at the clinic for ten years when she was promoted."], a:0, exp:"Past perfect continuous: had + been + verb-ing. 'For ten years' shows duration before the promotion."},
      {id:"papc027", type:"mc", q:"'The roads were wet because it ___ all night.'", options:["rained","had been raining","has been raining","was raining"], a:1, exp:"Past perfect continuous explains the cause of a past visible result (wet roads)."},
      {id:"papc028", type:"mc", q:"Which sentence emphasises the duration of an action before a past event?", options:["The team worked on the report before the deadline.","The team had been working on the report for weeks before the deadline.","The team has worked on the report before the deadline.","The team was working on the report before the deadline."], a:1, exp:"Past perfect continuous + 'for weeks' emphasises the ongoing duration before a past deadline."},
      {id:"papc029", type:"mc", q:"'By the time the new regulations took effect, factories ___ toxic waste for years.'", options:["dumped","had been dumping","have been dumping","were dumping"], a:1, exp:"'By the time' + 'for years' requires past perfect continuous for the ongoing action before the regulations."},
      {id:"papc030", type:"mc", q:"Choose the best option: 'He was out of breath because he ___.'", options:["had been running","has been running","ran","was running"], a:0, exp:"Past perfect continuous explains why he was out of breath (a visible past result caused by an ongoing action)."},
      {id:"papc031", type:"mc", q:"Which question is grammatically correct?", options:["Had she been waiting long when you arrived?","Had she been wait long when you arrived?","Was she had been waiting long when you arrived?","Did she had been waiting long when you arrived?"], a:0, exp:"Past perfect continuous question: 'Had + subject + been + verb-ing?'"},
      {id:"papc032", type:"mc", q:"'The students looked tired because they ___ all night for the exam.'", options:["studied","had studied","had been studying","have been studying"], a:2, exp:"Past perfect continuous emphasises the ongoing duration of studying that caused visible tiredness."},
      {id:"papc033", type:"mc", q:"Past perfect continuous vs past perfect: 'She ___ three chapters before dinner.' Which is more natural?", options:["had been reading (emphasises the activity)","had read (emphasises the completed amount)","Both are equally natural with no difference.","Neither is correct."], a:1, exp:"When a specific quantity is mentioned (three chapters), past perfect 'had read' is more natural because it emphasises completion."},
      {id:"papc034", type:"mc", q:"Choose the correct negative: 'The government ___ enough in education before the crisis.'", options:["had not been investing","had not been invest","has not been investing","did not been investing"], a:0, exp:"Negative past perfect continuous: had + not + been + verb-ing."},
      {id:"papc035", type:"mc", q:"'___ the scientists ___ the data for long before the error was discovered?'", options:["Had ... been collecting","Have ... been collecting","Were ... been collecting","Did ... been collecting"], a:0, exp:"Past perfect continuous question form: 'Had + subject + been + verb-ing?'"},
      {id:"papc036", type:"mc", q:"Which sentence correctly shows cause and effect?", options:["The ground was muddy because it had been raining all week.","The ground was muddy because it rained all week.","The ground was muddy because it has been raining all week.","The ground was muddy because it had rained all week."], a:0, exp:"Past perfect continuous best shows the ongoing rain (cause) leading to the visible result (muddy ground)."},
      {id:"papc037", type:"mc", q:"'She was exhausted. She ___ patients since 6 a.m.'", options:["treated","had been treating","has been treating","was treating"], a:1, exp:"Past perfect continuous explains the cause of past exhaustion with an action ongoing since a specific time."},
      {id:"papc038", type:"mc", q:"Which is NOT a signal word for past perfect continuous?", options:["for","since","already","all day"], a:2, exp:"'Already' typically signals past perfect (completion), not past perfect continuous (duration/ongoing)."},
      {id:"papc039", type:"mc", q:"'The pollution levels were dangerously high. Factories ___ chemicals into the river for months.'", options:["released","had released","had been releasing","have been releasing"], a:2, exp:"Past perfect continuous shows the ongoing release of chemicals that caused the dangerously high levels."},
      {id:"papc040", type:"mc", q:"Choose the correct form: 'By 2020, the organisation ___ clean energy solutions for over a decade.'", options:["promoted","had been promoting","has been promoting","was promoting"], a:1, exp:"'By 2020' (past) + 'for over a decade' (duration) requires past perfect continuous."},
      {id:"papc041", type:"mc", q:"When do we prefer past perfect continuous over past perfect?", options:["When we want to emphasise the result of a completed action.","When we want to emphasise the duration or ongoing nature of an activity.","When we describe a single, completed past event.","When we use reported speech."], a:1, exp:"Past perfect continuous emphasises duration or the ongoing nature of an activity, while past perfect emphasises completion."},
      {id:"papc042", type:"mc", q:"'Her voice was hoarse because she ___ lectures all day.'", options:["gave","had given","had been giving","has been giving"], a:2, exp:"Past perfect continuous explains the ongoing cause (giving lectures all day) of the visible past result (hoarse voice)."},
      {id:"papc043", type:"mc", q:"'How long ___ they ___ before the funding was approved?'", options:["had ... been waiting","have ... been waiting","did ... wait","were ... waiting"], a:0, exp:"'How long' asking about duration before a past event requires past perfect continuous."},
      {id:"papc044", type:"mc", q:"Which verb CANNOT typically be used in the continuous form?", options:["work","believe","study","run"], a:1, exp:"'Believe' is a stative verb and is not normally used in continuous tenses. Use 'had believed' instead of 'had been believing'."},
      {id:"papc045", type:"mc", q:"'The athlete ___ for the Olympics for four years when she finally qualified.'", options:["trained","had trained","had been training","was training"], a:2, exp:"'For four years' emphasises the duration of training leading up to qualifying, requiring past perfect continuous."},
      {id:"papc046", type:"mc", q:"'The government ___ about reform for years, but nothing had changed.'", options:["talked","had talked","had been talking","has been talking"], a:2, exp:"Past perfect continuous shows the ongoing (and perhaps fruitless) nature of talking over years."},
      {id:"papc047", type:"mc", q:"Select the correct sentence:", options:["She had been knowing him for years before they worked together.","She had known him for years before they worked together.","She has been knowing him for years before they worked together.","She had been knew him for years before they worked together."], a:1, exp:"'Know' is a stative verb and cannot be used in continuous form. Use past perfect 'had known'."},
      {id:"papc048", type:"mc", q:"'The soil had eroded badly. Water ___ through the area for weeks.'", options:["had been flowing","flowed","has been flowing","was flowing"], a:0, exp:"Past perfect continuous explains the ongoing cause (water flowing) of the past result (eroded soil)."},
      {id:"papc049", type:"mc", q:"'By the time the doctor arrived, the patient ___ for almost an hour.'", options:["waited","had been waiting","has been waiting","waits"], a:1, exp:"'By the time' + 'for almost an hour' requires past perfect continuous for the ongoing action before the doctor's arrival."},
      {id:"papc050", type:"mc", q:"Which is correct? 'The researchers ___. That is why their report was so thorough.'", options:["had been investigating the issue for months","investigated the issue for months","have been investigating the issue for months","were investigating the issue for months"], a:0, exp:"Past perfect continuous shows the extended investigation that caused the thoroughness of the report."},
      {id:"papc051", type:"error", q:"She has been teaching at the school for five years when she decided to resign.", a:"She had been teaching at the school for five years when she decided to resign.", exp:"'When she decided' (past) requires past perfect continuous, not present perfect continuous, for the ongoing earlier action."},
      {id:"papc052", type:"error", q:"The children had been play outside all afternoon before it started to rain.", a:"The children had been playing outside all afternoon before it started to rain.", exp:"Past perfect continuous requires 'had been + verb-ing'. 'Play' should be 'playing'."},
      {id:"papc053", type:"error", q:"By the time the new policy was introduced, citizens had been waited for a solution for years.", a:"By the time the new policy was introduced, citizens had been waiting for a solution for years.", exp:"Past perfect continuous: 'had been + verb-ing'. 'Waited' (past participle) should be 'waiting' (present participle)."},
      {id:"papc054", type:"error", q:"The students were tired because they have been studying since early morning.", a:"The students were tired because they had been studying since early morning.", exp:"The result is in the past ('were tired'), so the cause must also be past: 'had been studying', not 'have been studying'."},
      {id:"papc055", type:"error", q:"He had been knowing the professor for years before he became her research assistant.", a:"He had known the professor for years before he became her research assistant.", exp:"'Know' is a stative verb and cannot be used in the continuous form. Use past perfect 'had known'."},
      {id:"papc056", type:"error", q:"The company had been operate in the region for a decade before the merger.", a:"The company had been operating in the region for a decade before the merger.", exp:"Past perfect continuous requires 'had been + verb-ing'. 'Operate' should be 'operating'."},
      {id:"papc057", type:"error", q:"The air quality was poor. Factories had been release emissions without proper filters.", a:"The air quality was poor. Factories had been releasing emissions without proper filters.", exp:"Past perfect continuous: 'had been + verb-ing'. 'Release' should be 'releasing'."},
      {id:"papc058", type:"error", q:"Scientists had been been monitoring sea levels for years before the alarming data emerged.", a:"Scientists had been monitoring sea levels for years before the alarming data emerged.", exp:"'Had been been' is a repetition error. The correct form is 'had been monitoring'."},
      {id:"papc059", type:"error", q:"She did not had been feeling well for days before she finally visited the doctor.", a:"She had not been feeling well for days before she finally visited the doctor.", exp:"Negative past perfect continuous: 'had + not + been + verb-ing'. 'Did not had been' is incorrect."},
      {id:"papc060", type:"error", q:"The government had been spend billions on infrastructure before the audit revealed waste.", a:"The government had been spending billions on infrastructure before the audit revealed waste.", exp:"Past perfect continuous requires 'had been + verb-ing'. 'Spend' should be 'spending'."},
      {id:"papc061", type:"error", q:"Water had been leaking from the pipes since weeks, causing extensive damage.", a:"Water had been leaking from the pipes for weeks, causing extensive damage.", exp:"Use 'for' with duration periods (weeks, months, years). 'Since' is used with specific points in time (since Monday, since 2020)."},
      {id:"papc062", type:"error", q:"The researchers had been collecting data since three years before the breakthrough.", a:"The researchers had been collecting data for three years before the breakthrough.", exp:"'For' is used with durations (three years). 'Since' requires a specific point in time. This is a common Chinese-speaker error."},
      {id:"papc063", type:"error", q:"Had the team been working in the project for long before the deadline was extended?", a:"Had the team been working on the project for long before the deadline was extended?", exp:"The correct preposition is 'working on' (a project), not 'working in'. This is a common collocation error."},
      {id:"papc064", type:"error", q:"The athlete had been trained intensively for months when the injury occurred.", a:"The athlete had been training intensively for months when the injury occurred.", exp:"Past perfect continuous uses the present participle (-ing form). 'Trained' (past participle) should be 'training'."},
      {id:"papc065", type:"error", q:"By 2018, the organisation had been providing aid since ten years.", a:"By 2018, the organisation had been providing aid for ten years.", exp:"Use 'for' with duration (ten years), not 'since'. 'Since' needs a specific time point (since 2008)."},
      {id:"papc066", type:"error", q:"The students had been prepared for the test all week when it was postponed.", a:"The students had been preparing for the test all week when it was postponed.", exp:"Past perfect continuous requires 'had been + verb-ing'. Use 'preparing' (present participle), not 'prepared'."},
      {id:"papc067", type:"error", q:"Pollution had being increasing in the city for years before the clean air act was passed.", a:"Pollution had been increasing in the city for years before the clean air act was passed.", exp:"Past perfect continuous: 'had been + verb-ing'. 'Being' should be 'been'."},
      {id:"papc068", type:"error", q:"The lecturer's voice was strained because she had been been lecturing for three hours straight.", a:"The lecturer's voice was strained because she had been lecturing for three hours straight.", exp:"'Had been been' is a repetition error. Correct form is 'had been lecturing'."},
      {id:"papc069", type:"error", q:"They discussed the issue for hours, so they were very tired. (The discussion finished before they felt tired.)", a:"They had been discussing the issue for hours, so they were very tired.", exp:"To show the ongoing discussion caused the tiredness, past perfect continuous is needed."},
      {id:"papc070", type:"error", q:"The hospital had been providing free check-ups since five years when the programme was discontinued.", a:"The hospital had been providing free check-ups for five years when the programme was discontinued.", exp:"Use 'for' with duration (five years). 'Since' requires a specific time point. Australian spelling: 'programme'."},
      {id:"papc071", type:"transform", q:"The team worked on the environmental report for months. Then they presented it. [Combine using past perfect continuous]", a:"The team had been working on the environmental report for months before they presented it.", exp:"Past perfect continuous emphasises the duration of work before the presentation."},
      {id:"papc072", type:"transform", q:"She studied medicine for six years. She finally graduated. [Rewrite to emphasise duration using past perfect continuous]", a:"She had been studying medicine for six years when she finally graduated.", exp:"'When' links the ongoing action (studying) to the point of graduation."},
      {id:"papc073", type:"transform", q:"The factory polluted the river for decades. Regulators intervened. [Combine to show cause and effect]", a:"The factory had been polluting the river for decades before regulators finally intervened.", exp:"Past perfect continuous shows the long-term pollution that led to intervention."},
      {id:"papc074", type:"transform", q:"He was exhausted. He had marked exam papers all day. [Combine into one sentence showing cause]", a:"He was exhausted because he had been marking exam papers all day.", exp:"'Because' + past perfect continuous explains the cause of the past exhaustion."},
      {id:"papc075", type:"transform", q:"Citizens complained about traffic for years. The council built a bypass. [Combine using 'by the time']", a:"By the time the council built a bypass, citizens had been complaining about traffic for years.", exp:"'By the time' introduces the later event, with past perfect continuous for the ongoing earlier action."},
      {id:"papc076", type:"transform", q:"She lived in Melbourne for ten years. Then she moved to Sydney. [Rewrite emphasising the duration before moving]", a:"She had been living in Melbourne for ten years before she moved to Sydney.", exp:"Past perfect continuous with 'for ten years' emphasises the duration of living there."},
      {id:"papc077", type:"transform", q:"They negotiated the trade agreement for two years. It was finally signed. [Rewrite using 'when']", a:"They had been negotiating the trade agreement for two years when it was finally signed.", exp:"'When' connects the ongoing negotiation to the moment it was signed."},
      {id:"papc078", type:"transform", q:"The students revised the entire syllabus for a week. The exam was postponed. [Rewrite with past perfect continuous]", a:"The students had been revising the entire syllabus for a week when the exam was postponed.", exp:"Past perfect continuous shows the ongoing revision before the unexpected postponement."},
      {id:"papc079", type:"transform", q:"How long did the researchers collect data before the study was published? [Rewrite using past perfect continuous]", a:"How long had the researchers been collecting data before the study was published?", exp:"Past perfect continuous question form: 'How long + had + subject + been + verb-ing?'"},
      {id:"papc080", type:"transform", q:"The charity raised funds all year. The target was finally reached. [Combine to emphasise duration]", a:"The charity had been raising funds all year when the target was finally reached.", exp:"Past perfect continuous with 'all year' emphasises the extended duration of fundraising."},
      {id:"papc081", type:"transform", q:"His eyes were sore. He stared at the computer screen since morning. [Correct and combine as cause/effect]", a:"His eyes were sore because he had been staring at the computer screen since morning.", exp:"Past perfect continuous correctly explains the ongoing cause of the visible result."},
      {id:"papc082", type:"transform", q:"The nurse worked double shifts for three months. She requested a transfer. [Combine using 'before']", a:"The nurse had been working double shifts for three months before she requested a transfer.", exp:"Past perfect continuous shows the duration of working before the request."},
      {id:"papc083", type:"transform", q:"Climate scientists warned governments about rising sea levels for years. The summit finally took place. [Combine using 'by the time']", a:"By the time the summit finally took place, climate scientists had been warning governments about rising sea levels for years.", exp:"'By the time' + past perfect continuous shows the long-running warnings before the summit."},
      {id:"papc084", type:"transform", q:"The construction company built the hospital. It took four years. Then it was opened. [Rewrite emphasising duration]", a:"The construction company had been building the hospital for four years when it was finally opened.", exp:"Past perfect continuous with 'for four years' emphasises the long duration of the construction process."},
      {id:"papc085", type:"transform", q:"She felt dizzy. She had not eaten anything all day. [Combine showing cause and effect]", a:"She felt dizzy because she had not been eating anything all day.", exp:"Negative past perfect continuous ('had not been eating') explains the cause of the dizziness. 'All day' emphasises duration."}
    ]
  },

  /* ──────────────────────────────────────────────────────────────
     3. SIMPLE FUTURE (will)
     ────────────────────────────────────────────────────────────── */
  {
    id: "simple-future",
    name: "Simple Future (will)",
    formula: "Subject + will + base verb",
    negFormula: "Subject + will + not + base verb",
    qFormula: "Will + subject + base verb?",
    usage: ["Predictions", "Spontaneous decisions", "Promises and offers", "Future facts", "Formal announcements"],
    signalWords: ["tomorrow", "next week", "in the future", "soon", "one day", "probably", "I think", "I believe"],
    examples: {pos: "Technology will continue to transform education.", neg: "This will not happen overnight.", q: "Will technology transform education?"},
    exercises: [
      {id:"sf001", type:"fill", q:"Experts predict that renewable energy ___ (replace) fossil fuels within the next few decades.", a:"will replace", exp:"A prediction about the future uses 'will + base verb'."},
      {id:"sf002", type:"fill", q:"The government ___ (introduce) stricter emissions standards next year.", a:"will introduce", exp:"A planned future announcement uses 'will + base verb'. 'Next year' is a future time marker."},
      {id:"sf003", type:"fill", q:"I think online education ___ (become) even more popular in the coming years.", a:"will become", exp:"'I think' signals a personal prediction, which uses 'will + base verb'."},
      {id:"sf004", type:"fill", q:"The new hospital ___ (not / open) until the safety inspections are complete.", a:"will not open", exp:"Negative simple future: 'will not + base verb'. 'Until' marks the future condition."},
      {id:"sf005", type:"fill", q:"Climate change ___ (affect) global food production significantly by 2050.", a:"will affect", exp:"A prediction with a future time reference ('by 2050') uses 'will + base verb'."},
      {id:"sf006", type:"fill", q:"The university ___ (offer) new scholarships to international students starting next semester.", a:"will offer", exp:"A formal announcement about a future plan uses 'will + base verb'."},
      {id:"sf007", type:"fill", q:"Automation ___ (probably / create) new types of jobs that we cannot yet imagine.", a:"will probably create", exp:"'Probably' with a future prediction: 'will + probably + base verb'."},
      {id:"sf008", type:"fill", q:"The research team ___ (publish) their findings in a peer-reviewed journal next month.", a:"will publish", exp:"A planned future action with 'next month' uses 'will + base verb'."},
      {id:"sf009", type:"fill", q:"I promise I ___ (submit) the application before the deadline.", a:"will submit", exp:"Promises use 'will + base verb' to express commitment to a future action."},
      {id:"sf010", type:"fill", q:"Rising sea levels ___ (threaten) coastal communities in the near future.", a:"will threaten", exp:"A prediction about future consequences uses 'will + base verb'."},
      {id:"sf011", type:"fill", q:"The council ___ (not / approve) the development unless environmental concerns are addressed.", a:"will not approve", exp:"Negative simple future with a condition: 'will not + base verb' + 'unless'."},
      {id:"sf012", type:"fill", q:"Artificial intelligence ___ (transform) the healthcare industry over the next decade.", a:"will transform", exp:"A prediction about future change uses 'will + base verb'. 'Over the next decade' is the time marker."},
      {id:"sf013", type:"fill", q:"I believe that investment in education ___ (yield) long-term economic benefits.", a:"will yield", exp:"'I believe' introduces a personal prediction using 'will + base verb'."},
      {id:"sf014", type:"fill", q:"The new policy ___ (not / take) effect until January.", a:"will not take", exp:"Negative simple future: 'will not + base verb'. 'Until January' sets the future boundary."},
      {id:"sf015", type:"fill", q:"Advances in medical technology ___ (enable) earlier detection of diseases.", a:"will enable", exp:"A prediction about future capabilities uses 'will + base verb'."},
      {id:"sf016", type:"fill", q:"Don't worry — I ___ (help) you prepare for the speaking section of the PTE.", a:"will help", exp:"A spontaneous offer uses 'will + base verb'."},
      {id:"sf017", type:"fill", q:"Population growth ___ (put) additional pressure on public services.", a:"will put", exp:"A prediction about future consequences. Note 'put' is an irregular verb with the same base and past participle."},
      {id:"sf018", type:"fill", q:"The minister announced that the programme ___ (receive) additional funding.", a:"will receive", exp:"A formal announcement about a future allocation uses 'will + base verb'. Australian spelling: 'programme'."},
      {id:"sf019", type:"fill", q:"Without proper regulation, social media ___ (continue) to spread misinformation.", a:"will continue", exp:"A conditional prediction about the future: 'will + base verb'."},
      {id:"sf020", type:"fill", q:"The examination results ___ (be) available online from next Monday.", a:"will be", exp:"A formal future fact: 'will + be'. 'From next Monday' is the future time reference."},
      {id:"sf021", type:"fill", q:"Technological innovation ___ (undoubtedly / play) a key role in solving environmental challenges.", a:"will undoubtedly play", exp:"'Undoubtedly' is an adverb placed between 'will' and the base verb for emphasis."},
      {id:"sf022", type:"fill", q:"The charity ___ (not / stop) providing aid until every family has been supported.", a:"will not stop", exp:"Negative simple future expressing commitment: 'will not + base verb'."},
      {id:"sf023", type:"fill", q:"Researchers predict that global temperatures ___ (rise) by at least two degrees.", a:"will rise", exp:"A prediction introduced by 'researchers predict' uses 'will + base verb' in the that-clause."},
      {id:"sf024", type:"fill", q:"I ___ (do) my best to improve my pronunciation before the PTE test.", a:"will do", exp:"A promise or personal commitment: 'will + base verb'."},
      {id:"sf025", type:"fill", q:"The new transport link ___ (reduce) commuting times for thousands of workers.", a:"will reduce", exp:"A prediction about the impact of infrastructure uses 'will + base verb'."},
      {id:"sf026", type:"mc", q:"Choose the correct sentence:", options:["Technology will continues to evolve rapidly.","Technology will continue to evolve rapidly.","Technology will continued to evolve rapidly.","Technology will to continue to evolve rapidly."], a:1, exp:"After 'will', use the base form of the verb without 'to': 'will continue'."},
      {id:"sf027", type:"mc", q:"Which sentence expresses a spontaneous decision?", options:["I will be studying tonight.","I will have finished by then.","I'll help you carry those books.","I am going to help you carry those books."], a:2, exp:"'I'll help you' is a spontaneous offer made at the moment of speaking, a key use of 'will'."},
      {id:"sf028", type:"mc", q:"'The government ___ new environmental regulations next quarter.'", options:["will announces","will announce","will to announce","announce will"], a:1, exp:"Simple future: 'will + base verb' (announce, not announces)."},
      {id:"sf029", type:"mc", q:"Which is NOT a typical use of 'will' for simple future?", options:["Predictions","Spontaneous decisions","Planned arrangements (with specific time and place)","Promises"], a:2, exp:"Planned arrangements with specific time and place typically use present continuous ('I am meeting her at 3pm'), not 'will'."},
      {id:"sf030", type:"mc", q:"Choose the correct negative: 'The reform ___ overnight.'", options:["will not happens","will not happen","not will happen","does not will happen"], a:1, exp:"Negative simple future: 'will + not + base verb'."},
      {id:"sf031", type:"mc", q:"Which sentence makes a prediction?", options:["I will call you later.","She will lend you the book.","Experts believe sea levels will rise dramatically.","I will open the window for you."], a:2, exp:"'Experts believe ... will rise' is a prediction about the future based on evidence."},
      {id:"sf032", type:"mc", q:"'___ artificial intelligence replace human teachers in the future?'", options:["Does","Is","Will","Has"], a:2, exp:"Simple future question form: 'Will + subject + base verb?'"},
      {id:"sf033", type:"mc", q:"Choose the correct form: 'I ___ you as soon as I have the results.'", options:["will notify","will notifies","notify will","am notifying"], a:0, exp:"A promise about a future action uses 'will + base verb'. Note: the time clause uses present simple, not future."},
      {id:"sf034", type:"mc", q:"Which sentence uses 'will' for a future fact?", options:["I think it will rain tomorrow.","I'll have a coffee, please.","The sun will rise at 6:23 am tomorrow.","She will probably pass the exam."], a:2, exp:"The sun rising at a specific time is a certain future fact, not a prediction or decision."},
      {id:"sf035", type:"mc", q:"'If the government invests in education, literacy rates ___.'", options:["improve","will improve","improved","improving"], a:1, exp:"First conditional: 'if + present simple, will + base verb'. The result clause uses simple future."},
      {id:"sf036", type:"mc", q:"Which is the correct question form?", options:["Will the new policy reduce inequality?","Will the new policy reduces inequality?","Does the new policy will reduce inequality?","The new policy will reduce inequality?"], a:0, exp:"Simple future question: 'Will + subject + base verb?'"},
      {id:"sf037", type:"mc", q:"Choose the best option: 'Don't worry. The committee ___ your proposal carefully.'", options:["considers","will consider","is consider","considering"], a:1, exp:"A reassuring promise about the future uses 'will + base verb'."},
      {id:"sf038", type:"mc", q:"'Deforestation ___ biodiversity if it continues at the current rate.'", options:["will destroys","will destroy","destroyed","is destroying"], a:1, exp:"A conditional prediction: 'will + base verb' (destroy, not destroys)."},
      {id:"sf039", type:"mc", q:"Which adverb placement is correct?", options:["The population will probably exceed 10 billion.","The population probably will exceed 10 billion.","The population will exceed probably 10 billion.","Probably the population will exceed 10 billion."], a:0, exp:"Adverbs of probability (probably, certainly, likely) are placed between 'will' and the main verb."},
      {id:"sf040", type:"mc", q:"In formal academic writing, which is preferred?", options:["It's gonna affect global health.","It will affect global health.","It's going to affect global health.","It shall affect global health."], a:1, exp:"'Will' is the most appropriate for formal academic predictions. 'Gonna' is informal; 'shall' is archaic in most contexts."},
      {id:"sf041", type:"mc", q:"'The scholarship ___ tuition fees for the entire programme.'", options:["will covers","will cover","is going cover","covers will"], a:1, exp:"Simple future: 'will + base verb'. No '-s' ending on the verb after 'will'."},
      {id:"sf042", type:"mc", q:"Which sentence is a formal announcement?", options:["I'll grab a coffee.","The university will commence enrolment on 15 March.","She'll probably come to the party.","I think it will be fine."], a:1, exp:"Formal announcements use 'will + base verb' with specific details and formal vocabulary."},
      {id:"sf043", type:"mc", q:"'Without government intervention, emissions ___.'", options:["will not decreasing","will not decrease","not will decrease","will not decreased"], a:1, exp:"Negative simple future: 'will + not + base verb' (decrease)."},
      {id:"sf044", type:"mc", q:"Which time expression does NOT typically accompany simple future?", options:["next year","tomorrow","right now","in the future"], a:2, exp:"'Right now' indicates the present moment, not the future. It pairs with present continuous, not simple future."},
      {id:"sf045", type:"mc", q:"'She promised she ___ the report before Friday.'", options:["finishes","will finish","finished","had finished"], a:1, exp:"A promise about a future action (from the speaker's perspective) uses 'will + base verb'."},
      {id:"sf046", type:"mc", q:"What is the contracted negative form of 'will not'?", options:["willn't","won't","wouldn't","don't will"], a:1, exp:"The contracted negative of 'will not' is 'won't'. This is an irregular contraction."},
      {id:"sf047", type:"mc", q:"'One day, scientists ___ a cure for all forms of cancer.'", options:["discover","will discover","discovered","discovering"], a:1, exp:"'One day' is a future time marker that pairs with 'will + base verb' for predictions."},
      {id:"sf048", type:"mc", q:"Choose the sentence that is grammatically incorrect:", options:["Technology will transform healthcare.","She will not attend the conference.","Will they agree to the terms?","He will goes to the meeting."], a:3, exp:"After 'will', the base form is required: 'will go', not 'will goes'. No third-person -s after modal verbs."},
      {id:"sf049", type:"mc", q:"'If we ___ now, the problem will only get worse.' Choose the correct verb for the if-clause.", options:["won't act","don't act","will not act","aren't acting"], a:1, exp:"First conditional: 'if + present simple, will + base verb'. The if-clause uses present simple, not future."},
      {id:"sf050", type:"mc", q:"Which expresses a stronger certainty about the future?", options:["It might rain tomorrow.","It could rain tomorrow.","It will definitely rain tomorrow.","It may rain tomorrow."], a:2, exp:"'Will definitely' expresses strong certainty, while 'might', 'could', and 'may' express possibility."},
      {id:"sf051", type:"error", q:"Technology will continues to shape modern education in the coming decades.", a:"Technology will continue to shape modern education in the coming decades.", exp:"After 'will', use the base form: 'continue', not 'continues'. No third-person -s after modal verbs."},
      {id:"sf052", type:"error", q:"The new policy will not takes effect until the parliament approves it.", a:"The new policy will not take effect until the parliament approves it.", exp:"After 'will not', use the base form: 'take', not 'takes'."},
      {id:"sf053", type:"error", q:"If the government will invest more in healthcare, outcomes will improve.", a:"If the government invests more in healthcare, outcomes will improve.", exp:"First conditional: the if-clause uses present simple, not 'will'. Use 'invests', not 'will invest'."},
      {id:"sf054", type:"error", q:"The population of the city will probably to reach five million by 2030.", a:"The population of the city will probably reach five million by 2030.", exp:"After 'will', use the base form directly. No 'to' is needed: 'will reach', not 'will to reach'."},
      {id:"sf055", type:"error", q:"Experts believe that renewable energy will replaced fossil fuels eventually.", a:"Experts believe that renewable energy will replace fossil fuels eventually.", exp:"After 'will', use the base form: 'replace', not 'replaced' (past participle)."},
      {id:"sf056", type:"error", q:"The university will announces the scholarship recipients next week.", a:"The university will announce the scholarship recipients next week.", exp:"After 'will', use the base form: 'announce', not 'announces'."},
      {id:"sf057", type:"error", q:"She will not to attend the conference due to scheduling conflicts.", a:"She will not attend the conference due to scheduling conflicts.", exp:"After 'will not', use the base form directly. No 'to' is needed."},
      {id:"sf058", type:"error", q:"Does climate change will affect agricultural productivity?", a:"Will climate change affect agricultural productivity?", exp:"'Will' is already a modal verb; do not add 'does'. Question form: 'Will + subject + base verb?'"},
      {id:"sf059", type:"error", q:"I think the economy will improves once the new trade deal is signed.", a:"I think the economy will improve once the new trade deal is signed.", exp:"After 'will', the base form is required: 'improve', not 'improves'."},
      {id:"sf060", type:"error", q:"The minister said the government will provides additional funding for schools.", a:"The minister said the government will provide additional funding for schools.", exp:"After 'will', use the base form: 'provide', not 'provides'."},
      {id:"sf061", type:"error", q:"Unless action is taken, pollution will to continue rising.", a:"Unless action is taken, pollution will continue rising.", exp:"No 'to' after 'will'. The correct form is 'will continue', not 'will to continue'."},
      {id:"sf062", type:"error", q:"The research findings will be publish in a leading journal next month.", a:"The research findings will be published in a leading journal next month.", exp:"Future passive: 'will be + past participle'. 'Publish' should be 'published'."},
      {id:"sf063", type:"error", q:"Students who will study consistently will achieve better results.", a:"Students who study consistently will achieve better results.", exp:"In time/conditional clauses with 'who', use present simple, not 'will': 'who study', not 'who will study'."},
      {id:"sf064", type:"error", q:"The new health programme will benefits millions of citizens.", a:"The new health programme will benefit millions of citizens.", exp:"After 'will', use the base form: 'benefit', not 'benefits'. Australian spelling: 'programme'."},
      {id:"sf065", type:"error", q:"Automation will creating both opportunities and challenges in the labour market.", a:"Automation will create both opportunities and challenges in the labour market.", exp:"After 'will', use the base form: 'create', not 'creating'. Do not confuse with future continuous."},
      {id:"sf066", type:"error", q:"The city council will built a new community centre by next year.", a:"The city council will build a new community centre by next year.", exp:"After 'will', use the base form: 'build', not 'built' (past participle)."},
      {id:"sf067", type:"error", q:"If it will rain tomorrow, the outdoor event will be cancelled.", a:"If it rains tomorrow, the outdoor event will be cancelled.", exp:"First conditional: the if-clause uses present simple ('rains'), not 'will rain'. This is a very common error among Chinese speakers."},
      {id:"sf068", type:"error", q:"Online learning platforms will probably became more sophisticated in the future.", a:"Online learning platforms will probably become more sophisticated in the future.", exp:"After 'will', use the base form: 'become', not 'became' (past tense)."},
      {id:"sf069", type:"error", q:"The number of international students will likely to increase next year.", a:"The number of international students will likely increase next year.", exp:"After 'will likely', use the base form directly: 'increase', not 'to increase'."},
      {id:"sf070", type:"error", q:"The hospital will not opened new wards until the funding is secured.", a:"The hospital will not open new wards until the funding is secured.", exp:"After 'will not', use the base form: 'open', not 'opened'."},
      {id:"sf071", type:"transform", q:"Scientists predict rising global temperatures. [Rewrite using 'will']", a:"Scientists predict that global temperatures will rise.", exp:"The prediction is restructured with 'will + base verb' in the that-clause."},
      {id:"sf072", type:"transform", q:"The government plans to invest in renewable energy. [Rewrite as a formal announcement using 'will']", a:"The government will invest in renewable energy.", exp:"A formal announcement uses 'will + base verb' for a definitive future action."},
      {id:"sf073", type:"transform", q:"It is likely that automation creates new job categories. [Rewrite using 'will probably']", a:"Automation will probably create new job categories.", exp:"'Will probably + base verb' expresses a likely future outcome."},
      {id:"sf074", type:"transform", q:"Maybe the new curriculum improves student engagement. [Rewrite using 'will' to express prediction]", a:"The new curriculum will improve student engagement.", exp:"Replacing 'maybe' with 'will' turns a possibility into a confident prediction."},
      {id:"sf075", type:"transform", q:"The hospital is not going to reduce its staff. [Rewrite using 'will not']", a:"The hospital will not reduce its staff.", exp:"'Will not' replaces 'is not going to' for a more formal future negative."},
      {id:"sf076", type:"transform", q:"Do you think technology replaces teachers? [Rewrite as a future question using 'will']", a:"Will technology replace teachers?", exp:"Simple future question form: 'Will + subject + base verb?'"},
      {id:"sf077", type:"transform", q:"The conference is next Friday. (Make it a formal announcement.) [Rewrite using 'will']", a:"The conference will take place next Friday.", exp:"A formal announcement with 'will + base verb' and an appropriate verb ('take place')."},
      {id:"sf078", type:"transform", q:"Air quality does not improve without government action. [Rewrite as a conditional prediction using 'will']", a:"Air quality will not improve without government action.", exp:"A conditional future prediction uses 'will not + base verb'."},
      {id:"sf079", type:"transform", q:"Rising sea levels threaten coastal cities. (Make it a future prediction.) [Rewrite using 'will']", a:"Rising sea levels will threaten coastal cities.", exp:"Adding 'will' turns a present-tense statement into a future prediction."},
      {id:"sf080", type:"transform", q:"The university is going to offer more online courses. [Rewrite using 'will' for formal tone]", a:"The university will offer more online courses.", exp:"'Will' replaces 'is going to' for a more formal register suitable for academic writing."},
      {id:"sf081", type:"transform", q:"I promise to complete the essay by tomorrow. [Rewrite using 'will']", a:"I will complete the essay by tomorrow.", exp:"Promises are naturally expressed with 'will + base verb'."},
      {id:"sf082", type:"transform", q:"Healthcare spending is expected to increase. [Rewrite as an active prediction using 'will']", a:"Healthcare spending will increase.", exp:"Active voice with 'will' is more direct than the passive 'is expected to'."},
      {id:"sf083", type:"transform", q:"It is certain that the population exceeds nine billion by 2050. [Rewrite using 'will definitely']", a:"The population will definitely exceed nine billion by 2050.", exp:"'Will definitely' expresses strong certainty about a future prediction."},
      {id:"sf084", type:"transform", q:"Perhaps the new regulations reduce carbon emissions. [Rewrite using 'may' and then using 'will']", a:"The new regulations may reduce carbon emissions. / The new regulations will reduce carbon emissions.", exp:"'May' expresses possibility; 'will' expresses certainty. Choose based on how confident you are."},
      {id:"sf085", type:"transform", q:"The government does not plan to cut education funding. [Rewrite using 'will not']", a:"The government will not cut education funding.", exp:"'Will not' provides a clear, direct future negative suitable for formal announcements."}
    ]
  },

  /* ──────────────────────────────────────────────────────────────
     4. FUTURE CONTINUOUS
     ────────────────────────────────────────────────────────────── */
  {
    id: "future-continuous",
    name: "Future Continuous",
    formula: "Subject + will + be + verb-ing",
    negFormula: "Subject + will + not + be + verb-ing",
    qFormula: "Will + subject + be + verb-ing?",
    usage: ["Actions in progress at a future time", "Planned future events", "Polite enquiries", "Parallel future actions"],
    signalWords: ["at this time tomorrow", "at 8pm", "next Monday", "while", "when", "all day tomorrow", "this time next year"],
    examples: {pos: "This time next year, I will be working in Australia.", neg: "I will not be attending the meeting tomorrow.", q: "Will you be using the lab at 3pm?"},
    exercises: [
      {id:"fc001", type:"fill", q:"This time tomorrow, the students ___ (sit) their final examination.", a:"will be sitting", exp:"'This time tomorrow' signals an action in progress at a specific future time, requiring future continuous."},
      {id:"fc002", type:"fill", q:"At 10 am next Monday, the committee ___ (discuss) the new education policy.", a:"will be discussing", exp:"A specific future time ('at 10 am next Monday') requires future continuous for the action in progress at that moment."},
      {id:"fc003", type:"fill", q:"Next semester, more students ___ (use) digital textbooks instead of printed ones.", a:"will be using", exp:"Future continuous describes an expected ongoing situation in a future period."},
      {id:"fc004", type:"fill", q:"The research team ___ (collect) data throughout the summer.", a:"will be collecting", exp:"'Throughout the summer' indicates an extended future period, requiring future continuous."},
      {id:"fc005", type:"fill", q:"While the doctors ___ (attend) the conference, their colleagues ___ (cover) their shifts.", a:"will be attending ... will be covering", exp:"'While' connects two parallel future actions, both requiring future continuous."},
      {id:"fc006", type:"fill", q:"___ you ___ (use) the laboratory this afternoon? I need to book it.", a:"Will ... be using", exp:"A polite enquiry about someone's future plans uses future continuous question form."},
      {id:"fc007", type:"fill", q:"The government ___ (not / increase) taxes during the election period.", a:"will not be increasing", exp:"Negative future continuous: 'will not be + verb-ing' for an action not expected during a future period."},
      {id:"fc008", type:"fill", q:"This time next year, she ___ (study) for her PhD at a leading university.", a:"will be studying", exp:"'This time next year' is a classic trigger for future continuous — an action in progress at a future point."},
      {id:"fc009", type:"fill", q:"The hospital ___ (operate) at full capacity during the flu season.", a:"will be operating", exp:"Future continuous describes an expected ongoing state during a future period."},
      {id:"fc010", type:"fill", q:"When you arrive at the office, I ___ (wait) for you in the lobby.", a:"will be waiting", exp:"'When you arrive' sets a future time point; the action of waiting will be in progress at that moment."},
      {id:"fc011", type:"fill", q:"The professor ___ (lecture) all morning, so she will not be available until noon.", a:"will be lecturing", exp:"'All morning' indicates an action continuing throughout a future period."},
      {id:"fc012", type:"fill", q:"At this rate, factories ___ (produce) more waste than ever by the end of the decade.", a:"will be producing", exp:"Future continuous shows an ongoing action expected at a future point."},
      {id:"fc013", type:"fill", q:"The environmental agency ___ (monitor) air quality levels throughout the construction period.", a:"will be monitoring", exp:"'Throughout the construction period' signals a continuous future action over an extended time."},
      {id:"fc014", type:"fill", q:"___ the students ___ (take) their PTE exams next Saturday?", a:"Will ... be taking", exp:"Polite enquiry using future continuous question form: 'Will + subject + be + verb-ing?'"},
      {id:"fc015", type:"fill", q:"Don't call between 2 and 4 pm — I ___ (attend) a seminar on public health.", a:"will be attending", exp:"A specific future time slot indicates an action in progress, requiring future continuous."},
      {id:"fc016", type:"fill", q:"By next month, the construction crew ___ (work) on the new school building.", a:"will be working", exp:"Future continuous describes a planned ongoing action at a future point ('by next month')."},
      {id:"fc017", type:"fill", q:"While the minister ___ (address) parliament, protesters ___ (gather) outside.", a:"will be addressing ... will be gathering", exp:"Two parallel future actions connected by 'while' both use future continuous."},
      {id:"fc018", type:"fill", q:"The clinic ___ (not / accept) new patients during the renovation period.", a:"will not be accepting", exp:"Negative future continuous for an action not happening during a future period."},
      {id:"fc019", type:"fill", q:"In five years, millions of people ___ (rely) on telemedicine for their healthcare needs.", a:"will be relying", exp:"'In five years' sets a future time frame for an ongoing action, requiring future continuous."},
      {id:"fc020", type:"fill", q:"___ the council ___ (review) the planning applications this Thursday?", a:"Will ... be reviewing", exp:"A polite enquiry about a scheduled activity uses future continuous question form."},
      {id:"fc021", type:"fill", q:"The university ___ (host) an international education summit all week.", a:"will be hosting", exp:"'All week' describes a continuous action over an extended future period."},
      {id:"fc022", type:"fill", q:"At midnight tonight, scientists at the observatory ___ (observe) the lunar eclipse.", a:"will be observing", exp:"A specific future time ('at midnight tonight') requires future continuous for the action in progress."},
      {id:"fc023", type:"fill", q:"When the new term begins, teachers ___ (implement) the updated curriculum.", a:"will be implementing", exp:"'When the new term begins' sets a future reference point for an ongoing action."},
      {id:"fc024", type:"fill", q:"I ___ (not / work) on Friday afternoon, so we can schedule the meeting then.", a:"will not be working", exp:"Negative future continuous communicates availability by indicating an action not in progress."},
      {id:"fc025", type:"fill", q:"The charity ___ (distribute) food packages to vulnerable communities throughout the winter.", a:"will be distributing", exp:"'Throughout the winter' signals a continuous future action over an extended period."},
      {id:"fc026", type:"mc", q:"Choose the correct sentence:", options:["At 3 pm tomorrow, I will study in the library.","At 3 pm tomorrow, I will be studying in the library.","At 3 pm tomorrow, I will been studying in the library.","At 3 pm tomorrow, I will studying in the library."], a:1, exp:"A specific future time ('at 3 pm tomorrow') requires future continuous: 'will be + verb-ing'."},
      {id:"fc027", type:"mc", q:"Which sentence expresses a polite enquiry?", options:["Do you use the computer?","Will you be using the computer this afternoon?","You will use the computer?","Are you going to use the computer?"], a:1, exp:"Future continuous questions are used for polite enquiries about someone's plans without pressuring them."},
      {id:"fc028", type:"mc", q:"'While the nurses ___ patients, the doctors ___ in the operating theatre.'", options:["will attend ... will operate","will be attending ... will be operating","are attending ... are operating","attend ... operate"], a:1, exp:"Two parallel future actions connected by 'while' both require future continuous."},
      {id:"fc029", type:"mc", q:"Which is NOT a typical use of the future continuous?", options:["An action in progress at a specific future time","Parallel future actions","A completed action by a future deadline","Polite enquiries about plans"], a:2, exp:"Completed actions by a future deadline use future perfect, not future continuous."},
      {id:"fc030", type:"mc", q:"'This time next week, they ___ the new health programme.'", options:["will launch","will be launching","will have launched","launched"], a:1, exp:"'This time next week' signals an action in progress at that future moment, requiring future continuous."},
      {id:"fc031", type:"mc", q:"Choose the correct negative: 'The factory ___ during the holidays.'", options:["will not be operating","will not operating","will not be operate","will be not operating"], a:0, exp:"Negative future continuous: 'will + not + be + verb-ing'."},
      {id:"fc032", type:"mc", q:"Which question form is correct?", options:["Will be you attending the lecture?","Will you be attending the lecture?","Will you attending the lecture?","Be will you attending the lecture?"], a:1, exp:"Future continuous question: 'Will + subject + be + verb-ing?'"},
      {id:"fc033", type:"mc", q:"'At this rate, global sea levels ___ even faster by mid-century.'", options:["rise","will rise","will be rising","will have risen"], a:2, exp:"'At this rate' + 'by mid-century' suggests an ongoing process at a future point, requiring future continuous."},
      {id:"fc034", type:"mc", q:"Which sentence uses future continuous for a planned event?", options:["I will attend the conference.","I will be attending the conference next week.","I attended the conference.","I have been attending the conference."], a:1, exp:"Future continuous can describe pre-planned future events: 'will be attending' next week."},
      {id:"fc035", type:"mc", q:"'When you land in Sydney, I ___ at the airport.'", options:["wait","will wait","will be waiting","am wait"], a:2, exp:"The action of waiting will be in progress at the specific future moment of landing."},
      {id:"fc036", type:"mc", q:"Which verb CANNOT typically be used in the future continuous?", options:["study","teach","own","discuss"], a:2, exp:"'Own' is a stative verb and is not normally used in continuous tenses. Use 'will own' instead."},
      {id:"fc037", type:"mc", q:"'All day tomorrow, the team ___ presentations at the education forum.'", options:["gives","will give","will be giving","is giving"], a:2, exp:"'All day tomorrow' indicates continuous future activity, requiring future continuous."},
      {id:"fc038", type:"mc", q:"Choose the best option: '___ the government ___ the new health initiative next quarter?'", options:["Will ... implementing","Will ... be implementing","Does ... implement","Is ... implementing"], a:1, exp:"Future continuous question for a planned event: 'Will + subject + be + verb-ing?'"},
      {id:"fc039", type:"mc", q:"'She ___ on her thesis all weekend, so do not disturb her.'", options:["works","will work","will be working","has worked"], a:2, exp:"'All weekend' signals an ongoing action over a future period, requiring future continuous."},
      {id:"fc040", type:"mc", q:"Which pair of sentences both correctly use future continuous?", options:["She will be teach. / He will be learn.","She will be teaching. / He will be learning.","She will teaching. / He will learning.","She be will teaching. / He be will learning."], a:1, exp:"Future continuous: 'will + be + verb-ing'. Both verbs need the -ing form."},
      {id:"fc041", type:"mc", q:"'In 2030, more students ___ courses entirely online.'", options:["take","will take","will be taking","took"], a:2, exp:"'In 2030' sets a future time when the action will be ongoing, requiring future continuous."},
      {id:"fc042", type:"mc", q:"What is the difference between 'I will write the report' and 'I will be writing the report at 8 pm'?", options:["No difference — they are interchangeable.","The first is a promise; the second describes an action in progress at a specific time.","The first is past; the second is future.","The first is formal; the second is informal."], a:1, exp:"Simple future states the action will happen; future continuous specifies it will be in progress at a particular time."},
      {id:"fc043", type:"mc", q:"'Don't phone me between 6 and 7. I ___ dinner.'", options:["will have","will be having","have","had"], a:1, exp:"Future continuous for an action in progress during a specific future time window."},
      {id:"fc044", type:"mc", q:"Which sentence is grammatically incorrect?", options:["They will be travelling to Melbourne next Monday.","She will be presenting her research at 2 pm.","He will be own a new car by then.","We will be celebrating the results tomorrow evening."], a:2, exp:"'Own' is a stative verb and cannot be used in continuous form. It should be 'He will own'."},
      {id:"fc045", type:"mc", q:"'By the time you wake up, I ___ to the airport.'", options:["drive","will drive","will be driving","will have driven"], a:2, exp:"The action of driving will be in progress when the other person wakes up, requiring future continuous."},
      {id:"fc046", type:"mc", q:"Choose the most natural response: 'What will you be doing at noon tomorrow?'", options:["I will be attending a workshop on environmental policy.","I attend a workshop.","I am attended a workshop.","I will attending a workshop."], a:0, exp:"The response matches the question's tense (future continuous): 'will be attending'."},
      {id:"fc047", type:"mc", q:"'While some countries ___ emissions, others ___ industrialisation.'", options:["will reduce ... will pursue","will be reducing ... will be pursuing","reduce ... pursue","reduced ... pursued"], a:1, exp:"Two parallel future actions connected by 'while' both use future continuous."},
      {id:"fc048", type:"mc", q:"Which is a polite way to ask about someone's schedule?", options:["Are you free tomorrow?","Will you be free tomorrow?","Will you be working late tomorrow?","You work late tomorrow?"], a:2, exp:"Future continuous questions sound more polite and less direct when asking about plans."},
      {id:"fc049", type:"mc", q:"'Next year at this time, the country ___ a major economic transformation.'", options:["undergoes","will undergo","will be undergoing","has undergone"], a:2, exp:"'Next year at this time' signals an action in progress at a future point, requiring future continuous."},
      {id:"fc050", type:"mc", q:"Which adverb placement is correct with future continuous?", options:["She will still be working at midnight.","She still will be working at midnight.","She will be still working at midnight.","She will be working still at midnight."], a:0, exp:"'Still' is placed between 'will' and 'be': 'will still be working'."},
      {id:"fc051", type:"error", q:"At this time next week, I will been travelling to Sydney for the conference.", a:"At this time next week, I will be travelling to Sydney for the conference.", exp:"Future continuous: 'will be + verb-ing', not 'will been + verb-ing'."},
      {id:"fc052", type:"error", q:"The students will be take their exams at 9 am tomorrow.", a:"The students will be taking their exams at 9 am tomorrow.", exp:"Future continuous requires the -ing form: 'will be taking', not 'will be take'."},
      {id:"fc053", type:"error", q:"While the doctor will examining the patient, the nurse will be preparing the medication.", a:"While the doctor will be examining the patient, the nurse will be preparing the medication.", exp:"Both parallel actions need future continuous: 'will be examining', not 'will examining'."},
      {id:"fc054", type:"error", q:"Will you be work on the project this weekend?", a:"Will you be working on the project this weekend?", exp:"Future continuous question: 'Will + subject + be + verb-ing?' Use 'working', not 'work'."},
      {id:"fc055", type:"error", q:"I will not be go to the library tomorrow because it is closed.", a:"I will not be going to the library tomorrow because it is closed.", exp:"Negative future continuous: 'will not be + verb-ing'. Use 'going', not 'go'."},
      {id:"fc056", type:"error", q:"This time next year, millions of students will be learn through virtual reality.", a:"This time next year, millions of students will be learning through virtual reality.", exp:"Future continuous: 'will be + verb-ing'. Use 'learning', not 'learn'."},
      {id:"fc057", type:"error", q:"The government will be introduces new health regulations next month.", a:"The government will be introducing new health regulations next month.", exp:"Future continuous: 'will be + verb-ing'. Use 'introducing', not 'introduces'."},
      {id:"fc058", type:"error", q:"At 3 pm, the committee will be discuss the environmental report.", a:"At 3 pm, the committee will be discussing the environmental report.", exp:"Future continuous: 'will be + verb-ing'. Use 'discussing', not 'discuss'."},
      {id:"fc059", type:"error", q:"She will be knowing the results by tomorrow afternoon.", a:"She will know the results by tomorrow afternoon.", exp:"'Know' is a stative verb and cannot be used in continuous form. Use simple future: 'will know'."},
      {id:"fc060", type:"error", q:"The hospital will be not accepting visitors during the quarantine period.", a:"The hospital will not be accepting visitors during the quarantine period.", exp:"Negative future continuous: 'will + not + be + verb-ing'. 'Not' comes before 'be'."},
      {id:"fc061", type:"error", q:"At this time tomorrow, I will be sat in the examination hall.", a:"At this time tomorrow, I will be sitting in the examination hall.", exp:"Future continuous requires the -ing form: 'will be sitting', not 'will be sat'. 'Sat' is past participle."},
      {id:"fc062", type:"error", q:"Next semester, the professor will be teach an advanced course on public policy.", a:"Next semester, the professor will be teaching an advanced course on public policy.", exp:"Future continuous: 'will be + verb-ing'. Use 'teaching', not 'teach'."},
      {id:"fc063", type:"error", q:"The environmental agency will monitoring pollution levels throughout the year.", a:"The environmental agency will be monitoring pollution levels throughout the year.", exp:"Future continuous: 'will be + verb-ing'. 'Be' is missing between 'will' and 'monitoring'."},
      {id:"fc064", type:"error", q:"While we will be travelling, our colleagues will works on the proposal.", a:"While we will be travelling, our colleagues will be working on the proposal.", exp:"Both parallel actions need future continuous: 'will be working', not 'will works'."},
      {id:"fc065", type:"error", q:"I will be owning my own home by the time I am forty.", a:"I will own my own home by the time I am forty.", exp:"'Own' is a stative verb and cannot be used in continuous form. Use simple future 'will own'. Also, 'by the time' often pairs with future perfect."},
      {id:"fc066", type:"error", q:"Will be the researchers presenting their findings at the symposium?", a:"Will the researchers be presenting their findings at the symposium?", exp:"Future continuous question: 'Will + subject + be + verb-ing?' Subject comes between 'Will' and 'be'."},
      {id:"fc067", type:"error", q:"The city council will be build new affordable housing throughout the next year.", a:"The city council will be building new affordable housing throughout the next year.", exp:"Future continuous: 'will be + verb-ing'. Use 'building', not 'build'."},
      {id:"fc068", type:"error", q:"At noon, the health minister will be made an important announcement.", a:"At noon, the health minister will be making an important announcement.", exp:"Future continuous: 'will be + verb-ing'. Use 'making', not 'made' (past participle)."},
      {id:"fc069", type:"error", q:"Don't disturb her this evening — she will be prepare for the PTE speaking test.", a:"Don't disturb her this evening — she will be preparing for the PTE speaking test.", exp:"Future continuous: 'will be + verb-ing'. Use 'preparing', not 'prepare'."},
      {id:"fc070", type:"error", q:"The charity will been distributing food to families affected by the flood.", a:"The charity will be distributing food to families affected by the flood.", exp:"Future continuous: 'will be + verb-ing', not 'will been + verb-ing'."},
      {id:"fc071", type:"transform", q:"I study at 8 pm every evening. (Make it about tomorrow specifically.) [Rewrite using future continuous]", a:"I will be studying at 8 pm tomorrow evening.", exp:"Future continuous places the action in progress at a specific future time."},
      {id:"fc072", type:"transform", q:"The team works on the environmental report all week. (Make it about next week.) [Rewrite using future continuous]", a:"The team will be working on the environmental report all next week.", exp:"Future continuous for an ongoing action over a future period."},
      {id:"fc073", type:"transform", q:"Are you using the conference room at 2 pm? (Make it more polite.) [Rewrite using future continuous]", a:"Will you be using the conference room at 2 pm?", exp:"Future continuous questions are more polite for enquiries about someone's plans."},
      {id:"fc074", type:"transform", q:"She attends a medical conference while her assistant manages the clinic. (Make it about next week.) [Rewrite using future continuous]", a:"She will be attending a medical conference while her assistant will be managing the clinic.", exp:"Two parallel future actions both use future continuous, connected by 'while'."},
      {id:"fc075", type:"transform", q:"Right now I am preparing for the PTE exam. (Shift to this time next month.) [Rewrite using future continuous]", a:"This time next month, I will be preparing for the PTE exam.", exp:"'This time next month' shifts the present continuous action to future continuous."},
      {id:"fc076", type:"transform", q:"The university hosts an open day. (Make it about next Saturday.) [Rewrite using future continuous]", a:"The university will be hosting an open day next Saturday.", exp:"Future continuous describes a planned future event at a specific time."},
      {id:"fc077", type:"transform", q:"Doctors treat patients throughout the night during the emergency. (Make it about tonight.) [Rewrite using future continuous]", a:"Doctors will be treating patients throughout the night tonight.", exp:"Future continuous for a continuous action over an extended future period."},
      {id:"fc078", type:"transform", q:"I don't work on Friday afternoon. (Make it about this Friday.) [Rewrite using negative future continuous]", a:"I will not be working on Friday afternoon.", exp:"Negative future continuous: 'will not be + verb-ing'."},
      {id:"fc079", type:"transform", q:"The government implements new education standards. (Make it about next year.) [Rewrite using future continuous]", a:"The government will be implementing new education standards next year.", exp:"Future continuous describes an action in progress during a future period."},
      {id:"fc080", type:"transform", q:"She teaches a seminar on public health every Tuesday. (Make it about next Tuesday.) [Rewrite using future continuous]", a:"She will be teaching a seminar on public health next Tuesday.", exp:"Future continuous for a specific planned event at a future time."},
      {id:"fc081", type:"transform", q:"What do you do at 10 am tomorrow? (Rewrite as a polite enquiry.) [Rewrite using future continuous]", a:"What will you be doing at 10 am tomorrow?", exp:"Future continuous questions are softer and more polite for enquiring about plans."},
      {id:"fc082", type:"transform", q:"Construction workers build the new library all summer. (Make it about this coming summer.) [Rewrite using future continuous]", a:"Construction workers will be building the new library all summer.", exp:"'All summer' signals ongoing activity over a future period, requiring future continuous."},
      {id:"fc083", type:"transform", q:"While the council debates the budget, residents wait for answers. (Make it about next Monday.) [Rewrite using future continuous]", a:"While the council will be debating the budget next Monday, residents will be waiting for answers.", exp:"Two parallel future actions connected by 'while' both use future continuous."},
      {id:"fc084", type:"transform", q:"Students sit their exams at this time next week. [Rewrite using future continuous]", a:"Students will be sitting their exams at this time next week.", exp:"'At this time next week' is a classic future continuous trigger for an action in progress."},
      {id:"fc085", type:"transform", q:"The health department conducts inspections throughout the month. (Make it about next month.) [Rewrite using future continuous]", a:"The health department will be conducting inspections throughout next month.", exp:"Future continuous for an ongoing planned activity over a future period."}
    ]
  },

  /* ──────────────────────────────────────────────────────────────
     5. FUTURE PERFECT
     ────────────────────────────────────────────────────────────── */
  {
    id: "future-perfect",
    name: "Future Perfect",
    formula: "Subject + will + have + past participle",
    negFormula: "Subject + will + not + have + past participle",
    qFormula: "Will + subject + have + past participle?",
    usage: ["Actions completed before a future time", "Assumptions about the past from a future perspective", "Achievement by a deadline"],
    signalWords: ["by", "by the time", "before", "by next year", "by then", "by tomorrow", "within"],
    examples: {pos: "By 2030, renewable energy will have replaced most fossil fuels.", neg: "They will not have completed the project by Friday.", q: "Will she have graduated by June?"},
    exercises: [
      {id:"fp001", type:"fill", q:"By the end of this year, the government ___ (implement) the new education policy.", a:"will have implemented", exp:"'By the end of this year' sets a future deadline before which the action will be completed."},
      {id:"fp002", type:"fill", q:"She ___ (complete) her PhD by the time she turns thirty.", a:"will have completed", exp:"'By the time' + present simple sets a future point by which the action will be finished."},
      {id:"fp003", type:"fill", q:"By 2030, scientists ___ (develop) more effective treatments for chronic diseases.", a:"will have developed", exp:"'By 2030' sets a future deadline for the completed development."},
      {id:"fp004", type:"fill", q:"The construction team ___ (finish) the new hospital before the end of next year.", a:"will have finished", exp:"'Before the end of next year' indicates completion prior to a future deadline."},
      {id:"fp005", type:"fill", q:"By the time you arrive, I ___ (already / prepare) all the documents.", a:"will have already prepared", exp:"'By the time' + 'already' emphasises that the preparation will be completed before arrival."},
      {id:"fp006", type:"fill", q:"The university ___ (not / finalise) the timetable by Monday.", a:"will not have finalised", exp:"Negative future perfect: 'will not have + past participle'. Australian spelling: 'finalise'."},
      {id:"fp007", type:"fill", q:"___ the researchers ___ (publish) their findings by the conference date?", a:"Will ... have published", exp:"Future perfect question: 'Will + subject + have + past participle?'"},
      {id:"fp008", type:"fill", q:"By next month, the charity ___ (raise) enough funds to build the community centre.", a:"will have raised", exp:"'By next month' sets a future deadline for the completion of fundraising."},
      {id:"fp009", type:"fill", q:"The students ___ (submit) their dissertations before the summer break begins.", a:"will have submitted", exp:"'Before' sets the future point by which submission will be completed."},
      {id:"fp010", type:"fill", q:"By the time the new regulations take effect, many factories ___ (already / close).", a:"will have already closed", exp:"'By the time' + 'already' signals completion before the future event."},
      {id:"fp011", type:"fill", q:"Within five years, the city ___ (transform) its public transport network.", a:"will have transformed", exp:"'Within five years' sets a timeframe for completion, requiring future perfect."},
      {id:"fp012", type:"fill", q:"By graduation, she ___ (study) at three different universities.", a:"will have studied", exp:"'By graduation' is the future deadline by which the studying will be completed."},
      {id:"fp013", type:"fill", q:"The environmental agency ___ (not / complete) the assessment by the deadline.", a:"will not have completed", exp:"Negative future perfect shows the action will remain incomplete at the future deadline."},
      {id:"fp014", type:"fill", q:"By the time autonomous vehicles become common, engineers ___ (solve) most safety issues.", a:"will have solved", exp:"'By the time' + present simple sets the future point by which solving will be complete."},
      {id:"fp015", type:"fill", q:"Before the election, the party ___ (announce) its education reform plan.", a:"will have announced", exp:"'Before the election' indicates the announcement will be completed prior to that future event."},
      {id:"fp016", type:"fill", q:"By next week, the hospital ___ (vaccinate) over ten thousand residents.", a:"will have vaccinated", exp:"'By next week' sets the future deadline for the completed vaccination count."},
      {id:"fp017", type:"fill", q:"The programme ___ (not / achieve) its targets by the scheduled review date.", a:"will not have achieved", exp:"Negative future perfect: the targets will remain unmet at the review date. Australian spelling: 'programme'."},
      {id:"fp018", type:"fill", q:"By the time the report is due, the team ___ (analyse) all the data.", a:"will have analysed", exp:"'By the time' sets the deadline; future perfect shows analysis will be complete. Australian spelling: 'analysed'."},
      {id:"fp019", type:"fill", q:"Within a decade, technology ___ (revolutionise) the way we access healthcare.", a:"will have revolutionised", exp:"'Within a decade' sets the timeframe for completed transformation. Australian spelling: 'revolutionise'."},
      {id:"fp020", type:"fill", q:"___ the council ___ (approve) the budget by the time parliament reconvenes?", a:"Will ... have approved", exp:"Future perfect question about completion before a future event."},
      {id:"fp021", type:"fill", q:"By December, he ___ (teach) at the school for exactly ten years.", a:"will have taught", exp:"'By December' + 'for ten years' indicates a duration reaching completion at a future point."},
      {id:"fp022", type:"fill", q:"The researchers ___ (gather) sufficient evidence before presenting their case.", a:"will have gathered", exp:"'Before presenting' sets the future point by which evidence gathering will be complete."},
      {id:"fp023", type:"fill", q:"By the end of the trial, the new medication ___ (be) tested on over five hundred patients.", a:"will have been", exp:"Future perfect passive: 'will have been + past participle'. The medication is tested by others."},
      {id:"fp024", type:"fill", q:"Before the summit begins, delegates ___ (review) the proposed climate agreement.", a:"will have reviewed", exp:"'Before' indicates the review will be completed prior to the summit."},
      {id:"fp025", type:"fill", q:"By 2035, Australia ___ (invest) billions in sustainable energy infrastructure.", a:"will have invested", exp:"'By 2035' sets the future deadline by which the investment will be completed."},
      {id:"fp026", type:"mc", q:"Choose the correct sentence:", options:["By next year, she will have graduate from university.","By next year, she will have graduated from university.","By next year, she will has graduated from university.","By next year, she will graduated from university."], a:1, exp:"Future perfect: 'will + have + past participle' (graduated). No '-d' dropping or 'has' after 'will'."},
      {id:"fp027", type:"mc", q:"'By the time the policy takes effect, the government ___ public consultations.'", options:["will complete","will have completed","will be completing","completes"], a:1, exp:"'By the time' + present simple requires future perfect for the action completed before that point."},
      {id:"fp028", type:"mc", q:"Which sentence correctly uses future perfect?", options:["By 2040, we will have been eliminate poverty.","By 2040, we will have eliminated poverty.","By 2040, we will eliminated poverty.","By 2040, we will have eliminating poverty."], a:1, exp:"Future perfect: 'will + have + past participle' (eliminated)."},
      {id:"fp029", type:"mc", q:"'___ the hospital ___ the renovation by the time flu season starts?'", options:["Will ... have completed","Will ... complete","Has ... completed","Does ... complete"], a:0, exp:"Future perfect question: 'Will + subject + have + past participle?'"},
      {id:"fp030", type:"mc", q:"Choose the correct negative: 'They ___ the bridge by December.'", options:["will not have built","will have not built","will not built","not will have built"], a:0, exp:"Negative future perfect: 'will + not + have + past participle'."},
      {id:"fp031", type:"mc", q:"Which time expression does NOT typically trigger future perfect?", options:["by next year","before the deadline","right now","within a decade"], a:2, exp:"'Right now' refers to the present, not a future deadline. Future perfect needs a future reference point."},
      {id:"fp032", type:"mc", q:"'Before the conference begins, the organisers ___ all the logistics.'", options:["arranged","will arrange","will have arranged","have arranged"], a:2, exp:"'Before' + future event requires future perfect for the completed earlier action."},
      {id:"fp033", type:"mc", q:"'By the end of the programme, participants ___ essential skills in data analysis.'", options:["will gain","will have gained","gained","gain"], a:1, exp:"'By the end of the programme' sets a future deadline for the completed skill acquisition. Australian spelling: 'programme'."},
      {id:"fp034", type:"mc", q:"Which is the correct future perfect passive?", options:["The report will have been completed by Friday.","The report will have been complete by Friday.","The report will been have completed by Friday.","The report will have completing by Friday."], a:0, exp:"Future perfect passive: 'will + have + been + past participle' (completed)."},
      {id:"fp035", type:"mc", q:"'By the time the semester ends, students ___ over 200 hours of practical training.'", options:["complete","will complete","will have completed","completed"], a:2, exp:"'By the time' + present simple requires future perfect for the action completed before that point."},
      {id:"fp036", type:"mc", q:"What is the difference between 'will finish' and 'will have finished'?", options:["No difference.","'Will finish' states a future action; 'will have finished' emphasises completion before a future point.","'Will finish' is formal; 'will have finished' is informal.","'Will have finished' is past tense."], a:1, exp:"Simple future states something will happen; future perfect emphasises completion before a specific future deadline."},
      {id:"fp037", type:"mc", q:"'By 2050, the population ___ the ten-billion mark.'", options:["will surpass","will have surpassed","surpasses","has surpassed"], a:1, exp:"'By 2050' sets a future deadline, requiring future perfect for an action completed by then."},
      {id:"fp038", type:"mc", q:"Choose the correct form: 'She ___ three novels by her thirtieth birthday.'", options:["will write","will have written","will have wrote","writes"], a:1, exp:"Future perfect: 'will have + past participle' (written, not wrote). 'By her thirtieth birthday' is the deadline."},
      {id:"fp039", type:"mc", q:"'Before the new law is enacted, the committee ___ it thoroughly.'", options:["will review","will have reviewed","reviews","reviewed"], a:1, exp:"'Before' + future event requires future perfect for the action that will be complete by then."},
      {id:"fp040", type:"mc", q:"Which sentence is grammatically incorrect?", options:["By Friday, they will have submitted the proposal.","She will not have finished the assignment by tomorrow.","Will you have completed the course by June?","By next year, he will have went to ten countries."], a:3, exp:"'Went' is simple past; the correct past participle is 'gone': 'will have gone'."},
      {id:"fp041", type:"mc", q:"'Within the next decade, renewable energy ___ a dominant role in the power grid.'", options:["plays","will play","will have assumed","assumed"], a:2, exp:"'Within the next decade' + future perfect shows a completed transition by the end of that period."},
      {id:"fp042", type:"mc", q:"'By the time the students graduate, they ___ extensive research experience.'", options:["gain","will gain","will have gained","gained"], a:2, exp:"'By the time' + present simple sets the future point by which experience will be fully gained."},
      {id:"fp043", type:"mc", q:"Choose the correct question: '___ the environmental targets ___ by the review date?'", options:["Will ... have been met","Will ... met","Have ... been met","Will ... have meet"], a:0, exp:"Future perfect passive question: 'Will + subject + have + been + past participle?'"},
      {id:"fp044", type:"mc", q:"'By tomorrow morning, the hospital ___ over fifty emergency patients.'", options:["treats","will treat","will have treated","treated"], a:2, exp:"'By tomorrow morning' sets the future deadline for the completed number of treatments."},
      {id:"fp045", type:"mc", q:"'She ___ all the required modules before she applies for the position.'", options:["will complete","will have completed","completes","completed"], a:1, exp:"'Before she applies' sets the future point by which module completion will be done."},
      {id:"fp046", type:"mc", q:"Which sentence correctly uses future perfect to express achievement?", options:["By June, I will passed all my exams.","By June, I will have passed all my exams.","By June, I will be passed all my exams.","By June, I have will passed all my exams."], a:1, exp:"Future perfect: 'will + have + past participle'. 'Will passed' and 'will be passed' are incorrect forms."},
      {id:"fp047", type:"mc", q:"'By the end of the decade, the city ___ its carbon emissions by 40%.'", options:["reduces","will reduce","will have reduced","reduced"], a:2, exp:"'By the end of the decade' requires future perfect for a completed reduction by that deadline."},
      {id:"fp048", type:"mc", q:"Which is correct? 'Before the audit, the accountant ___.'", options:["will have reconciled all accounts","reconciled all accounts","will reconcile have all accounts","has reconciled all accounts"], a:0, exp:"'Before the audit' (future event) requires future perfect for the action completed prior to it."},
      {id:"fp049", type:"mc", q:"'The charity ___ its fundraising goal by Christmas.' Choose the negative form.", options:["will not have reached","will have not reached","not will have reached","will not reached"], a:0, exp:"Negative future perfect: 'will + not + have + past participle'."},
      {id:"fp050", type:"mc", q:"What is the structure of the future perfect passive?", options:["will + have + been + past participle","will + be + have + past participle","will + have + being + past participle","will + been + have + past participle"], a:0, exp:"Future perfect passive: 'will + have + been + past participle'. Example: 'The bridge will have been built by 2028.'"},
      {id:"fp051", type:"error", q:"By next year, the school will have introduce a new curriculum.", a:"By next year, the school will have introduced a new curriculum.", exp:"Future perfect requires the past participle: 'introduced', not the base form 'introduce'."},
      {id:"fp052", type:"error", q:"She will has completed her degree by the time she starts working.", a:"She will have completed her degree by the time she starts working.", exp:"After 'will', use 'have' (not 'has'). Modal verbs are always followed by the base form."},
      {id:"fp053", type:"error", q:"By 2040, technology will have been transform education completely.", a:"By 2040, technology will have transformed education completely.", exp:"Active future perfect: 'will have + past participle'. If passive were intended: 'will have been transformed'."},
      {id:"fp054", type:"error", q:"Before the deadline, the team will have submit their research proposal.", a:"Before the deadline, the team will have submitted their research proposal.", exp:"Future perfect: 'will have + past participle'. 'Submit' should be 'submitted'."},
      {id:"fp055", type:"error", q:"By the end of the semester, we will completed all required coursework.", a:"By the end of the semester, we will have completed all required coursework.", exp:"Future perfect: 'will + have + past participle'. 'Have' is missing between 'will' and 'completed'."},
      {id:"fp056", type:"error", q:"The government will not have build enough affordable housing by 2030.", a:"The government will not have built enough affordable housing by 2030.", exp:"'Built' is the correct past participle of 'build'. 'Build' is the base form."},
      {id:"fp057", type:"error", q:"Will the hospital have been complete by the time flu season begins?", a:"Will the hospital have been completed by the time flu season begins?", exp:"Future perfect passive: 'will have been + past participle'. 'Complete' should be 'completed'."},
      {id:"fp058", type:"error", q:"By tomorrow, the committee will have review all the applications.", a:"By tomorrow, the committee will have reviewed all the applications.", exp:"Future perfect: 'will have + past participle'. 'Review' should be 'reviewed'."},
      {id:"fp059", type:"error", q:"The researchers will have analyse the data before the presentation.", a:"The researchers will have analysed the data before the presentation.", exp:"Future perfect: 'will have + past participle'. 'Analyse' should be 'analysed'. Australian spelling."},
      {id:"fp060", type:"error", q:"By the end of next year, the organisation will have been raised over a million dollars.", a:"By the end of next year, the organisation will have raised over a million dollars.", exp:"Active voice is needed here (the organisation raises money). 'Will have raised', not passive 'will have been raised'."},
      {id:"fp061", type:"error", q:"Before the new law takes effect, hundreds of businesses will closed.", a:"Before the new law takes effect, hundreds of businesses will have closed.", exp:"Future perfect: 'will + have + past participle'. 'Have' is missing."},
      {id:"fp062", type:"error", q:"By 2050, sea levels will have rose significantly due to climate change.", a:"By 2050, sea levels will have risen significantly due to climate change.", exp:"'Risen' is the correct past participle of 'rise'. 'Rose' is the simple past form."},
      {id:"fp063", type:"error", q:"The programme will have not achieved its targets by the review date.", a:"The programme will not have achieved its targets by the review date.", exp:"Negative future perfect: 'will + not + have + past participle'. 'Not' comes before 'have', not after."},
      {id:"fp064", type:"error", q:"Within five years, renewable energy will have became the primary power source.", a:"Within five years, renewable energy will have become the primary power source.", exp:"'Become' is the correct past participle (same as base form). 'Became' is simple past."},
      {id:"fp065", type:"error", q:"By the time the policy is reviewed, it will have been implement for two years.", a:"By the time the policy is reviewed, it will have been implemented for two years.", exp:"Future perfect passive: 'will have been + past participle'. 'Implement' should be 'implemented'."},
      {id:"fp066", type:"error", q:"The students will have took all their final exams before the holidays.", a:"The students will have taken all their final exams before the holidays.", exp:"'Taken' is the correct past participle of 'take'. 'Took' is simple past."},
      {id:"fp067", type:"error", q:"By the time I retire, I will have been work in education for thirty years.", a:"By the time I retire, I will have worked in education for thirty years.", exp:"Future perfect active: 'will have + past participle'. 'Work' should be 'worked'. (Or future perfect continuous: 'will have been working'.)"},
      {id:"fp068", type:"error", q:"By 2035, the city council will have spend over two billion dollars on infrastructure.", a:"By 2035, the city council will have spent over two billion dollars on infrastructure.", exp:"'Spent' is the correct past participle of 'spend'. 'Spend' is the base form."},
      {id:"fp069", type:"error", q:"Before the audit begins, the company will have prepare all financial statements.", a:"Before the audit begins, the company will have prepared all financial statements.", exp:"Future perfect: 'will have + past participle'. 'Prepare' should be 'prepared'."},
      {id:"fp070", type:"error", q:"By the time she graduates, she will have wrote her thesis on environmental policy.", a:"By the time she graduates, she will have written her thesis on environmental policy.", exp:"'Written' is the correct past participle of 'write'. 'Wrote' is simple past."},
      {id:"fp071", type:"transform", q:"The university finishes the building project. The deadline is December. [Combine using future perfect with 'by']", a:"The university will have finished the building project by December.", exp:"Future perfect with 'by' shows completion before the deadline."},
      {id:"fp072", type:"transform", q:"She completes all her coursework. Then she applies for the internship. [Rewrite using 'before' + future perfect]", a:"She will have completed all her coursework before she applies for the internship.", exp:"Future perfect for the action completed before the future event of applying."},
      {id:"fp073", type:"transform", q:"The government reduces carbon emissions by 30%. The target year is 2030. [Combine using future perfect]", a:"By 2030, the government will have reduced carbon emissions by 30%.", exp:"'By 2030' sets the future deadline for the completed reduction."},
      {id:"fp074", type:"transform", q:"Researchers discover new treatments for diabetes. This happens before the next decade ends. [Rewrite using future perfect]", a:"Researchers will have discovered new treatments for diabetes before the next decade ends.", exp:"Future perfect shows the discovery will be complete before the decade ends."},
      {id:"fp075", type:"transform", q:"The hospital vaccinates all residents. This is expected to happen by next month. [Rewrite using future perfect]", a:"The hospital will have vaccinated all residents by next month.", exp:"'By next month' sets the future deadline for completed vaccination."},
      {id:"fp076", type:"transform", q:"They do not finish the environmental report. The deadline is Friday. [Rewrite as negative future perfect]", a:"They will not have finished the environmental report by Friday.", exp:"Negative future perfect: 'will not have + past participle' with a future deadline."},
      {id:"fp077", type:"transform", q:"Does the team submit the proposal before the meeting? [Rewrite as a future perfect question]", a:"Will the team have submitted the proposal before the meeting?", exp:"Future perfect question: 'Will + subject + have + past participle?'"},
      {id:"fp078", type:"transform", q:"The new bridge is built. This is expected by 2028. [Rewrite using future perfect passive]", a:"The new bridge will have been built by 2028.", exp:"Future perfect passive: 'will have been + past participle'."},
      {id:"fp079", type:"transform", q:"She publishes five research papers. This happens by the time she applies for tenure. [Rewrite using future perfect]", a:"She will have published five research papers by the time she applies for tenure.", exp:"'By the time' sets the future point by which publication will be complete."},
      {id:"fp080", type:"transform", q:"The school implements the new digital learning strategy. The expected completion is within six months. [Rewrite using future perfect]", a:"The school will have implemented the new digital learning strategy within six months.", exp:"'Within six months' sets the timeframe for completion, requiring future perfect."},
      {id:"fp081", type:"transform", q:"The economy recovers from the recession. Experts predict this by the middle of next year. [Rewrite using future perfect]", a:"Experts predict that the economy will have recovered from the recession by the middle of next year.", exp:"Future perfect in a prediction with 'by' showing expected completion."},
      {id:"fp082", type:"transform", q:"All the exams are marked by the end of the week. (Make it a question.) [Rewrite using future perfect passive question]", a:"Will all the exams have been marked by the end of the week?", exp:"Future perfect passive question: 'Will + subject + have + been + past participle?'"},
      {id:"fp083", type:"transform", q:"The government launches five new health initiatives. This happens before the end of its term. [Rewrite using future perfect]", a:"The government will have launched five new health initiatives before the end of its term.", exp:"'Before the end of its term' sets the future deadline for the completed launches."},
      {id:"fp084", type:"transform", q:"He teaches at the university for twenty years. The milestone is reached next June. [Rewrite using future perfect]", a:"By next June, he will have taught at the university for twenty years.", exp:"'By next June' sets the future point at which the duration milestone is reached."},
      {id:"fp085", type:"transform", q:"The environmental targets are met. The review is scheduled for 2032. [Rewrite as a negative future perfect — the targets will NOT be met]", a:"The environmental targets will not have been met by the 2032 review.", exp:"Negative future perfect passive: 'will not have been + past participle'."}
    ]
  },

  /* ──────────────────────────────────────────────────────────────
     6. FUTURE PERFECT CONTINUOUS
     ────────────────────────────────────────────────────────────── */
  {
    id: "future-perfect-continuous",
    name: "Future Perfect Continuous",
    formula: "Subject + will + have + been + verb-ing",
    negFormula: "Subject + will + not + have + been + verb-ing",
    qFormula: "Will + subject + have + been + verb-ing?",
    usage: ["Duration of ongoing action up to a future point", "Emphasising how long by a future time", "Explaining future cause/effect"],
    signalWords: ["for", "by", "by the time", "by next year", "when", "how long"],
    examples: {pos: "By December, she will have been teaching for five years.", neg: "He will not have been waiting that long.", q: "Will you have been living here for ten years by 2030?"},
    exercises: [
      {id:"fpc001", type:"fill", q:"By next March, she ___ (teach) at the university for exactly ten years.", a:"will have been teaching", exp:"'By next March' + 'for ten years' emphasises the duration of an ongoing action up to a future point."},
      {id:"fpc002", type:"fill", q:"By the time the project is completed, the team ___ (work) on it for three years.", a:"will have been working", exp:"'By the time' + 'for three years' requires future perfect continuous to emphasise duration."},
      {id:"fpc003", type:"fill", q:"When she retires next year, she ___ (practise) medicine for over thirty years.", a:"will have been practising", exp:"'When she retires' + 'for over thirty years' highlights the duration up to the future retirement point. Australian spelling: 'practise'."},
      {id:"fpc004", type:"fill", q:"By 2030, the government ___ (invest) in renewable energy for two decades.", a:"will have been investing", exp:"'By 2030' + 'for two decades' shows the ongoing investment duration up to that future point."},
      {id:"fpc005", type:"fill", q:"By the end of this semester, I ___ (study) English for four years.", a:"will have been studying", exp:"'By the end of this semester' + 'for four years' emphasises continuous study duration."},
      {id:"fpc006", type:"fill", q:"He ___ (research) climate change for fifteen years by the time he publishes his book.", a:"will have been researching", exp:"'By the time' sets the future point; 'for fifteen years' shows duration of ongoing research."},
      {id:"fpc007", type:"fill", q:"By next Monday, the construction workers ___ (build) the new school for six months.", a:"will have been building", exp:"'By next Monday' + 'for six months' emphasises the ongoing construction duration."},
      {id:"fpc008", type:"fill", q:"When the new hospital opens, doctors ___ (plan) it for over five years.", a:"will have been planning", exp:"The planning started in the past and will continue as an ongoing activity up to the opening."},
      {id:"fpc009", type:"fill", q:"By tomorrow evening, the negotiators ___ (talk) for over twelve hours.", a:"will have been talking", exp:"'By tomorrow evening' + 'for over twelve hours' shows the extended duration of talks."},
      {id:"fpc010", type:"fill", q:"By the time you join the company, I ___ (work) here for five years.", a:"will have been working", exp:"'By the time' + 'for five years' emphasises ongoing employment duration up to a future point."},
      {id:"fpc011", type:"fill", q:"The charity ___ (operate) in the region for a decade by the end of this year.", a:"will have been operating", exp:"'By the end of this year' + 'for a decade' highlights the ongoing operation duration."},
      {id:"fpc012", type:"fill", q:"She ___ (not / wait) long by the time the bus arrives.", a:"will not have been waiting", exp:"Negative future perfect continuous: 'will not have been + verb-ing'."},
      {id:"fpc013", type:"fill", q:"By June, the patients ___ (receive) treatment at the clinic for six months.", a:"will have been receiving", exp:"'By June' + 'for six months' shows the ongoing duration of treatment."},
      {id:"fpc014", type:"fill", q:"How long ___ you ___ (live) in Australia by the time you apply for citizenship?", a:"will ... have been living", exp:"'How long' + future perfect continuous asks about the duration of an ongoing action up to a future point."},
      {id:"fpc015", type:"fill", q:"By the time the election takes place, the candidates ___ (campaign) for months.", a:"will have been campaigning", exp:"'By the time' + 'for months' emphasises the ongoing campaign duration before the election."},
      {id:"fpc016", type:"fill", q:"The scientists ___ (collect) environmental data for two years by the time the report is published.", a:"will have been collecting", exp:"'For two years' + 'by the time' highlights the extended duration of data collection."},
      {id:"fpc017", type:"fill", q:"By next week, the volunteers ___ (distribute) food packages for an entire month.", a:"will have been distributing", exp:"'By next week' + 'for an entire month' shows the duration of ongoing distribution."},
      {id:"fpc018", type:"fill", q:"When the funding runs out, the programme ___ (support) disadvantaged students for five years.", a:"will have been supporting", exp:"The ongoing support has a duration ('for five years') that reaches a future endpoint. Australian spelling: 'programme'."},
      {id:"fpc019", type:"fill", q:"By the time I take the PTE exam, I ___ (prepare) for it for three months.", a:"will have been preparing", exp:"'By the time' + 'for three months' emphasises the preparation duration up to the exam."},
      {id:"fpc020", type:"fill", q:"She will be exhausted because she ___ (mark) essays for eight hours straight by 6 pm.", a:"will have been marking", exp:"Future perfect continuous explains the future cause (marking for hours) of the future effect (exhaustion)."},
      {id:"fpc021", type:"fill", q:"By the time the policy review happens, the community ___ (advocate) for change for years.", a:"will have been advocating", exp:"'By the time' + 'for years' emphasises the ongoing duration of advocacy."},
      {id:"fpc022", type:"fill", q:"The nurse ___ (care) for patients in the emergency ward for a full day by the end of her shift.", a:"will have been caring", exp:"'By the end of her shift' + 'for a full day' highlights the duration of the ongoing activity."},
      {id:"fpc023", type:"fill", q:"By 2035, the city ___ (implement) its sustainability plan for a decade.", a:"will have been implementing", exp:"'By 2035' + 'for a decade' shows the ongoing implementation duration."},
      {id:"fpc024", type:"fill", q:"When the semester ends, the students ___ (attend) lectures for sixteen weeks.", a:"will have been attending", exp:"'When the semester ends' + 'for sixteen weeks' emphasises the duration of attendance."},
      {id:"fpc025", type:"fill", q:"By the time the cure is found, researchers ___ (search) for it for decades.", a:"will have been searching", exp:"'By the time' + 'for decades' emphasises the extremely long duration of ongoing research."},
      {id:"fpc026", type:"mc", q:"Choose the correct sentence:", options:["By May, I will have been work here for two years.","By May, I will have been working here for two years.","By May, I will been have working here for two years.","By May, I will have working here for two years."], a:1, exp:"Future perfect continuous: 'will + have + been + verb-ing'. All four components must be present and in order."},
      {id:"fpc027", type:"mc", q:"'By the time the conference starts, the organiser ___ for six months.'", options:["will plan","will be planning","will have been planning","plans"], a:2, exp:"'By the time' + 'for six months' requires future perfect continuous to show duration up to the future event."},
      {id:"fpc028", type:"mc", q:"Which sentence correctly emphasises duration up to a future point?", options:["By next year, she will teach for a decade.","By next year, she will have been teaching for a decade.","By next year, she teaches for a decade.","By next year, she will be teaching for a decade."], a:1, exp:"Future perfect continuous with 'for a decade' emphasises the ongoing duration of teaching."},
      {id:"fpc029", type:"mc", q:"'She will be tired because she ___ all day.' Which is best?", options:["will study","will be studying","will have been studying","studies"], a:2, exp:"Future perfect continuous explains the cause (ongoing studying all day) of a future effect (tiredness)."},
      {id:"fpc030", type:"mc", q:"Which question is grammatically correct?", options:["Will you have been living here for ten years by 2030?","Will you have been live here for ten years by 2030?","Have will you been living here for ten years by 2030?","Will you been have living here for ten years by 2030?"], a:0, exp:"Future perfect continuous question: 'Will + subject + have + been + verb-ing?'"},
      {id:"fpc031", type:"mc", q:"'By Friday, the committee ___ the issue for an entire week.'", options:["will discuss","will be discussing","will have been discussing","discussed"], a:2, exp:"'By Friday' + 'for an entire week' requires future perfect continuous for the duration of ongoing discussion."},
      {id:"fpc032", type:"mc", q:"Choose the correct negative: 'He ___ long enough to qualify for the pension by then.'", options:["will not have been working","will not been have working","will have not been working","not will have been working"], a:0, exp:"Negative future perfect continuous: 'will + not + have + been + verb-ing'."},
      {id:"fpc033", type:"mc", q:"When do we choose future perfect continuous over future perfect?", options:["When we want to emphasise completion.","When we want to emphasise the duration of an ongoing activity up to a future point.","When we describe a single completed event.","When we make a promise."], a:1, exp:"Future perfect continuous emphasises ongoing duration; future perfect emphasises completion."},
      {id:"fpc034", type:"mc", q:"'By the time the ambulance arrives, the paramedics ___ first aid for twenty minutes.'", options:["will administer","will have administered","will have been administering","administer"], a:2, exp:"'By the time' + 'for twenty minutes' shows the ongoing duration of administering first aid."},
      {id:"fpc035", type:"mc", q:"Which sentence uses future perfect continuous to explain a future cause?", options:["He will finish the marathon tomorrow.","He will be running tomorrow morning.","He will have run 42 km by the end.","He will be exhausted because he will have been running for four hours."], a:3, exp:"Future perfect continuous explains the cause (running for hours) of the future result (exhaustion)."},
      {id:"fpc036", type:"mc", q:"Which verb CANNOT be used in future perfect continuous?", options:["work","belong","teach","study"], a:1, exp:"'Belong' is a stative verb and cannot be used in continuous tenses. Use 'will have belonged' instead."},
      {id:"fpc037", type:"mc", q:"'How long ___ the researchers ___ the experiment by the time results are available?'", options:["will ... have been conducting","will ... be conducting","have ... been conducting","will ... have conducted"], a:0, exp:"'How long' + 'by the time' requires future perfect continuous for the duration of an ongoing action."},
      {id:"fpc038", type:"mc", q:"'By next month, the factory ___ emissions for a full year without a single violation.'", options:["will monitor","will be monitoring","will have been monitoring","monitors"], a:2, exp:"'By next month' + 'for a full year' shows the ongoing monitoring duration up to that future point."},
      {id:"fpc039", type:"mc", q:"Which is correct? 'By the end of the day, she ___.'", options:["will have been teaching for eight hours","will have been teach for eight hours","will been have teaching for eight hours","will have teaching been for eight hours"], a:0, exp:"Future perfect continuous: 'will + have + been + verb-ing'. The components must be in this exact order."},
      {id:"fpc040", type:"mc", q:"'By the time the grant expires, the lab ___ this research for three years.'", options:["conducts","will conduct","will have been conducting","conducted"], a:2, exp:"'By the time' + 'for three years' requires future perfect continuous for ongoing research duration."},
      {id:"fpc041", type:"mc", q:"What is the full structure of future perfect continuous?", options:["will + be + have + verb-ing","will + have + been + verb-ing","will + have + be + verb-ing","will + been + have + verb-ing"], a:1, exp:"The correct order is: will + have + been + verb-ing. All four elements are required."},
      {id:"fpc042", type:"mc", q:"'The patients ___ the treatment for six weeks by the time the clinical trial ends.'", options:["receive","will receive","will have been receiving","received"], a:2, exp:"'By the time' + 'for six weeks' highlights the ongoing treatment duration, requiring future perfect continuous."},
      {id:"fpc043", type:"mc", q:"Choose the best response: 'Why will she look so tired after the exam period?'", options:["Because she will study.","Because she will be studying.","Because she will have been studying non-stop for two weeks.","Because she studied."], a:2, exp:"Future perfect continuous explains the cause (extended studying) of the anticipated future effect (looking tired)."},
      {id:"fpc044", type:"mc", q:"'By 2035, the environmental organisation ___ deforestation for twenty years.'", options:["will fight","will have fought","will have been fighting","fights"], a:2, exp:"'By 2035' + 'for twenty years' emphasises the ongoing fight, requiring future perfect continuous."},
      {id:"fpc045", type:"mc", q:"Which sentence pair correctly shows the difference between future perfect and future perfect continuous?", options:["'She will have read the book' (completion) vs 'She will have been reading the book for two hours' (duration).","Both forms are identical in meaning.","Future perfect continuous is more formal.","Future perfect is always preferred."], a:0, exp:"Future perfect emphasises completion (read the book); future perfect continuous emphasises ongoing duration (reading for two hours)."},
      {id:"fpc046", type:"mc", q:"'___ the team ___ on the environmental project for long by the time results are expected?'", options:["Will ... have been working","Have ... been working","Will ... work","Are ... working"], a:0, exp:"Future perfect continuous question: 'Will + subject + have + been + verb-ing?'"},
      {id:"fpc047", type:"mc", q:"Choose the correct form: 'By the time the bus comes, we ___ for forty minutes.'", options:["will wait","will be waiting","will have been waiting","waited"], a:2, exp:"'By the time' + 'for forty minutes' requires future perfect continuous to emphasise waiting duration."},
      {id:"fpc048", type:"mc", q:"Which signal word combination most clearly triggers future perfect continuous?", options:["yesterday + already","right now + currently","by next year + for five years","last week + before"], a:2, exp:"'By next year' (future deadline) + 'for five years' (duration) is the classic trigger for future perfect continuous."},
      {id:"fpc049", type:"mc", q:"'He will have been driving for twelve hours by the time he reaches Perth.' What does this emphasise?", options:["That he completed the trip","The duration of driving up to reaching Perth","That he drives fast","That he started driving recently"], a:1, exp:"Future perfect continuous emphasises how long the driving will have been going on by the time he arrives."},
      {id:"fpc050", type:"mc", q:"Which is NOT a use of future perfect continuous?", options:["Duration of an action up to a future point","Explaining a future cause/effect","Making a spontaneous decision","Emphasising how long something will have lasted"], a:2, exp:"Spontaneous decisions use simple future ('will + base verb'), not future perfect continuous."},
      {id:"fpc051", type:"error", q:"By next year, she will have been study medicine for six years.", a:"By next year, she will have been studying medicine for six years.", exp:"Future perfect continuous: 'will have been + verb-ing'. 'Study' should be 'studying'."},
      {id:"fpc052", type:"error", q:"By the time the law is passed, activists will been have fighting for equality for decades.", a:"By the time the law is passed, activists will have been fighting for equality for decades.", exp:"Correct order: 'will + have + been + verb-ing'. 'Been have' should be 'have been'."},
      {id:"fpc053", type:"error", q:"He will has been working at the hospital for twenty years by next June.", a:"He will have been working at the hospital for twenty years by next June.", exp:"After 'will', use 'have' (base form), not 'has'. Modal verbs are always followed by base forms."},
      {id:"fpc054", type:"error", q:"By the end of the month, the volunteers will have been distribute food for three weeks.", a:"By the end of the month, the volunteers will have been distributing food for three weeks.", exp:"Future perfect continuous: 'will have been + verb-ing'. 'Distribute' should be 'distributing'."},
      {id:"fpc055", type:"error", q:"She will have been owning the property for a decade by 2030.", a:"She will have owned the property for a decade by 2030.", exp:"'Own' is a stative verb and cannot be used in continuous tenses. Use future perfect: 'will have owned'."},
      {id:"fpc056", type:"error", q:"By the time the results are announced, students will have being waiting for weeks.", a:"By the time the results are announced, students will have been waiting for weeks.", exp:"'Been' not 'being'. Future perfect continuous: 'will + have + been + verb-ing'."},
      {id:"fpc057", type:"error", q:"The government will not have been invest in infrastructure for long enough by the election.", a:"The government will not have been investing in infrastructure for long enough by the election.", exp:"Future perfect continuous: 'will not have been + verb-ing'. 'Invest' should be 'investing'."},
      {id:"fpc058", type:"error", q:"By tomorrow, I will have been waited for the response for an entire week.", a:"By tomorrow, I will have been waiting for the response for an entire week.", exp:"Future perfect continuous requires the -ing form: 'waiting', not 'waited' (past participle)."},
      {id:"fpc059", type:"error", q:"How long will the researchers have been been conducting the trial by June?", a:"How long will the researchers have been conducting the trial by June?", exp:"'Been been' is a repetition error. The correct form is 'have been conducting'."},
      {id:"fpc060", type:"error", q:"By 2040, the charity will have been operate in the community for thirty years.", a:"By 2040, the charity will have been operating in the community for thirty years.", exp:"Future perfect continuous: 'will have been + verb-ing'. 'Operate' should be 'operating'."},
      {id:"fpc061", type:"error", q:"They will have been knowing each other for twenty years by next summer.", a:"They will have known each other for twenty years by next summer.", exp:"'Know' is a stative verb and cannot be used in continuous form. Use future perfect: 'will have known'."},
      {id:"fpc062", type:"error", q:"By the time the new curriculum is finalised, teachers will have been prepare for it since January.", a:"By the time the new curriculum is finalised, teachers will have been preparing for it since January.", exp:"Future perfect continuous: 'will have been + verb-ing'. 'Prepare' should be 'preparing'."},
      {id:"fpc063", type:"error", q:"She will have been living here since five years by next March.", a:"She will have been living here for five years by next March.", exp:"Use 'for' with durations (five years), not 'since'. 'Since' requires a specific point in time. Common Chinese-speaker error."},
      {id:"fpc064", type:"error", q:"By the deadline, the team will have been working in the proposal for months.", a:"By the deadline, the team will have been working on the proposal for months.", exp:"The correct preposition is 'working on' a proposal, not 'working in'. This is a common collocation error."},
      {id:"fpc065", type:"error", q:"By the time you arrive, I will have been cook dinner for an hour.", a:"By the time you arrive, I will have been cooking dinner for an hour.", exp:"Future perfect continuous: 'will have been + verb-ing'. 'Cook' should be 'cooking'."},
      {id:"fpc066", type:"error", q:"The scientist will have been research the topic for a decade by the time his findings are published.", a:"The scientist will have been researching the topic for a decade by the time his findings are published.", exp:"Future perfect continuous: 'will have been + verb-ing'. 'Research' should be 'researching'."},
      {id:"fpc067", type:"error", q:"Will the nurses have been working since twelve hours by the end of their shift?", a:"Will the nurses have been working for twelve hours by the end of their shift?", exp:"Use 'for' with duration (twelve hours). 'Since' needs a specific time point (since 6 am)."},
      {id:"fpc068", type:"error", q:"By next December, the organisation will have been fundraise for the hospital for two years.", a:"By next December, the organisation will have been fundraising for the hospital for two years.", exp:"Future perfect continuous: 'will have been + verb-ing'. 'Fundraise' should be 'fundraising'."},
      {id:"fpc069", type:"error", q:"The professor will have been teach at this institution for forty years by the time she retires.", a:"The professor will have been teaching at this institution for forty years by the time she retires.", exp:"Future perfect continuous: 'will have been + verb-ing'. 'Teach' should be 'teaching'."},
      {id:"fpc070", type:"error", q:"By 2028, the environmental agency will have been monitor water quality for a decade.", a:"By 2028, the environmental agency will have been monitoring water quality for a decade.", exp:"Future perfect continuous: 'will have been + verb-ing'. 'Monitor' should be 'monitoring'."},
      {id:"fpc071", type:"transform", q:"She teaches at the school. She started five years ago. By next year, that will be six years. [Rewrite using future perfect continuous]", a:"By next year, she will have been teaching at the school for six years.", exp:"Future perfect continuous with 'by next year' + 'for six years' shows the ongoing duration."},
      {id:"fpc072", type:"transform", q:"He works on his PhD thesis. He started three years ago. He expects to finish next year. [Rewrite using future perfect continuous with 'by the time']", a:"By the time he finishes, he will have been working on his PhD thesis for four years.", exp:"'By the time' + 'for four years' emphasises the extended duration of work on the thesis."},
      {id:"fpc073", type:"transform", q:"The government invests in education. It started in 2015. By 2030, it will be fifteen years. [Rewrite using future perfect continuous]", a:"By 2030, the government will have been investing in education for fifteen years.", exp:"'By 2030' + 'for fifteen years' shows the ongoing investment duration."},
      {id:"fpc074", type:"transform", q:"She will be very tired after the exam. She will study non-stop for twelve hours. [Combine to show cause using future perfect continuous]", a:"She will be very tired because she will have been studying non-stop for twelve hours.", exp:"Future perfect continuous explains the future cause (studying for hours) of the future effect (tiredness)."},
      {id:"fpc075", type:"transform", q:"How long does the team work on the project? The review is in March. [Rewrite as a future perfect continuous question]", a:"How long will the team have been working on the project by the time the review takes place in March?", exp:"'How long' + future perfect continuous asks about the duration of an ongoing action up to a future point."},
      {id:"fpc076", type:"transform", q:"The doctor practises medicine. She started twenty years ago. She retires next year. [Rewrite using future perfect continuous]", a:"By the time she retires next year, the doctor will have been practising medicine for over twenty years.", exp:"Australian spelling: 'practise'. Future perfect continuous emphasises the career duration. "},
      {id:"fpc077", type:"transform", q:"The hospital provides free vaccinations. It started six months ago. By next month, it will be seven months. [Rewrite using future perfect continuous]", a:"By next month, the hospital will have been providing free vaccinations for seven months.", exp:"'By next month' + 'for seven months' shows the ongoing provision duration."},
      {id:"fpc078", type:"transform", q:"Researchers collect ocean temperature data. They started in 2020. By 2030, it will be ten years. [Rewrite using future perfect continuous]", a:"By 2030, researchers will have been collecting ocean temperature data for ten years.", exp:"'By 2030' + 'for ten years' emphasises the duration of ongoing data collection."},
      {id:"fpc079", type:"transform", q:"He will not wait long. The appointment is soon. [Rewrite using negative future perfect continuous]", a:"He will not have been waiting long by the time his appointment begins.", exp:"Negative future perfect continuous: 'will not have been + verb-ing'."},
      {id:"fpc080", type:"transform", q:"The charity operates in rural areas. It started eight years ago. The anniversary is next year. [Rewrite using future perfect continuous]", a:"By next year, the charity will have been operating in rural areas for nine years.", exp:"Future perfect continuous with 'by next year' + 'for nine years' emphasises the ongoing duration."},
      {id:"fpc081", type:"transform", q:"The students attend the programme. They started in January. Graduation is in December. [Rewrite using future perfect continuous]", a:"By graduation in December, the students will have been attending the programme since January.", exp:"'Since January' marks the specific starting point of the ongoing attendance. Australian spelling: 'programme'."},
      {id:"fpc082", type:"transform", q:"She learns Mandarin. She started two years ago. Her trip to China is next month. [Rewrite using future perfect continuous]", a:"By the time she travels to China next month, she will have been learning Mandarin for over two years.", exp:"'By the time' + 'for over two years' emphasises the duration of language learning."},
      {id:"fpc083", type:"transform", q:"The factory releases emissions. It started years ago. The new regulation starts next quarter. [Rewrite using future perfect continuous]", a:"By the time the new regulation starts next quarter, the factory will have been releasing emissions for years.", exp:"Future perfect continuous highlights the long duration of emissions before the regulation."},
      {id:"fpc084", type:"transform", q:"His muscles will ache after the race. He will run for four hours. [Combine to show cause using future perfect continuous]", a:"His muscles will ache because he will have been running for four hours.", exp:"Future perfect continuous explains the future cause (running for hours) of the future effect (aching muscles)."},
      {id:"fpc085", type:"transform", q:"The nurse works night shifts. She started three months ago. By the time the roster changes, it will be six months. [Rewrite using future perfect continuous]", a:"By the time the roster changes, the nurse will have been working night shifts for six months.", exp:"'By the time' + 'for six months' emphasises the ongoing duration of night shifts up to the future roster change."}
    ]
  }
];
